function getEffectivePollResponseStatus(
  notes: string | null | undefined,
  imported?: ImportedPollResponseRecord | null
) {
  const inAppStatus = getPollResponseStatus(notes);
  if (!imported) return inAppStatus;

  const inAppTimestamp = Date.parse(getPollResponseTimestamp(notes) || "");
  const importedTimestamp = Date.parse(imported.responseSubmittedAt || "");

  if (Number.isNaN(inAppTimestamp) && Number.isNaN(importedTimestamp)) {
    return inAppStatus !== "no_response" ? inAppStatus : imported.responseStatus;
  }
  if (Number.isNaN(inAppTimestamp)) return imported.responseStatus;
  if (Number.isNaN(importedTimestamp)) return inAppStatus;
  return importedTimestamp >= inAppTimestamp ? imported.responseStatus : inAppStatus;
}

function parseImportedPollResponses(value?: string | null): ImportedPollResponseRecord[] {
  const text = asText(value);
  if (!text) return [] as ImportedPollResponseRecord[];
  try {
    const decoded = decodeURIComponent(text);
    const parsed = JSON.parse(decoded);
    if (!Array.isArray(parsed)) return [];
    return parsed
      .map((entry): ImportedPollResponseRecord => {
        const responseStatus = asText((entry as ImportedPollResponseRecord).responseStatus) as PollResponseStatus;
        return {
          name: asText((entry as ImportedPollResponseRecord).name),
          email: asText((entry as ImportedPollResponseRecord).email),
          normalizedEmail: normalizeEmail(asText((entry as ImportedPollResponseRecord).normalizedEmail || (entry as ImportedPollResponseRecord).email)),
          responseStatus:
            responseStatus === "available" || responseStatus === "maybe" || responseStatus === "not_available"
              ? responseStatus
              : "no_response",
          responseLabel: asText((entry as ImportedPollResponseRecord).responseLabel),
          responseSubmittedAt: asText((entry as ImportedPollResponseRecord).responseSubmittedAt),
          responseNote: asText((entry as ImportedPollResponseRecord).responseNote),
          matchedSpId: asText((entry as ImportedPollResponseRecord).matchedSpId),
          matchedSpEmail: asText((entry as ImportedPollResponseRecord).matchedSpEmail),
          matchedSpName: asText((entry as ImportedPollResponseRecord).matchedSpName),
          matchType:
            asText((entry as ImportedPollResponseRecord).matchType) === "sp_id"
              ? "sp_id"
              : asText((entry as ImportedPollResponseRecord).matchType) === "email"
              ? "email"
              : asText((entry as ImportedPollResponseRecord).matchType) === "name"
                ? "name"
                : "unmatched",
          matchConfidence: Number((entry as ImportedPollResponseRecord).matchConfidence) || 0,
          rawAnswer: asText((entry as ImportedPollResponseRecord).rawAnswer),
        };
      })
      .filter((entry) => entry.name || entry.email || entry.matchedSpId);
  } catch {
    return [];
  }
}

function getImportedPollMatchTypeLabel(matchType?: ImportedPollMatchType | null) {
  if (matchType === "sp_id") return "SP ID matched";
  if (matchType === "email") return "Email matched";
  if (matchType === "name") return "Name matched";
  return "";
}

function formatImportedPollAssignmentNote(note: string) {
  const cleaned = asText(note);
  return cleaned ? `Poll note: ${cleaned}` : "";
}

function normalizeAssignmentNoteForCompare(value: string) {
  return asText(value).toLowerCase().replace(/\s+/g, " ");
}

function mergeImportedPollNoteIntoAssignmentNotes(
  existingNotes: string | null | undefined,
  importedNote: string | null | undefined
) {
  const formattedPollNote = formatImportedPollAssignmentNote(asText(importedNote));
  const currentNotes = asText(existingNotes);
  if (!formattedPollNote) return currentNotes;
  if (!currentNotes) return formattedPollNote;

  const normalizedCurrent = normalizeAssignmentNoteForCompare(currentNotes);
  const normalizedRawNote = normalizeAssignmentNoteForCompare(importedNote || "");
  const normalizedFormattedNote = normalizeAssignmentNoteForCompare(formattedPollNote);
  if (
    normalizedCurrent.includes(normalizedFormattedNote) ||
    (normalizedRawNote && normalizedCurrent.includes(normalizedRawNote))
  ) {
    return currentNotes;
  }

  return `${currentNotes}\n\n${formattedPollNote}`;
}

function getRotationRoundKeyFromParts(
  sessionDate?: string | null,
  startTime?: string | null,
  endTime?: string | null
) {
  return [
    asText(sessionDate) || "date-tbd",
    asText(startTime) || "start-tbd",
    asText(endTime) || "end-tbd",
  ].join("|");
}

function getRotationRoundKeyFromSession(session: EventSessionRow) {
  return getRotationRoundKeyFromParts(session.session_date, session.start_time, session.end_time);
}

function getSnapshotRoundKey(roundNumber: number) {
  return `completed-snapshot-round-${roundNumber}`;
}

function getRoundNumberFromRotationKey(value: unknown) {
  const text = asText(value);
  const direct = Number(text);
  if (Number.isFinite(direct) && direct > 0) return direct;
  const match = text.match(/(?:^|[-_\s])round[-_\s]*(\d+)\b/i) || text.match(/\bround[-_\s]*(\d+)\b/i);
  if (match?.[1]) return Number(match[1]) || 0;
  return 0;
}

function timesMatch(left?: string | null, right?: string | null) {
  const leftMinutes = parseTimeToMinutes(left);
  const rightMinutes = parseTimeToMinutes(right);
  if (leftMinutes !== null && rightMinutes !== null) return leftMinutes === rightMinutes;
  return asText(left).toLowerCase() === asText(right).toLowerCase();
}

function resolveSelectedScheduleRound(args: {
  selectedRotationRound: RotationRound | null | undefined;
  resolvedRounds: ScheduleBuilderPreviewResolvedRound[];
  persistedResolvedRoundsByKey: Map<string, ScheduleBuilderPreviewResolvedRound>;
  selectedRoundIndex: number;
  selectedRoundGlobalIndex: number;
}) {
  const selectedRound = args.selectedRotationRound;
  if (!selectedRound || !args.resolvedRounds.length) return null;

  const exactKeyMatch = args.persistedResolvedRoundsByKey.get(selectedRound.key);
  if (exactKeyMatch) return exactKeyMatch;

  const selectedRoundRecord = selectedRound as RotationRound & { round?: unknown; roundNumber?: unknown };
  const explicitRoundNumber =
    parsePositiveInteger(selectedRoundRecord.round, 0) ||
    parsePositiveInteger(selectedRoundRecord.roundNumber, 0);
  const keyRoundNumber = getRoundNumberFromRotationKey(selectedRound.key);
  const globalRoundNumber = args.selectedRoundGlobalIndex >= 0 ? args.selectedRoundGlobalIndex + 1 : 0;
  const localRoundNumber = args.selectedRoundIndex >= 0 ? args.selectedRoundIndex + 1 : 0;
  const roundNumberCandidates = Array.from(
    new Set([explicitRoundNumber, keyRoundNumber, globalRoundNumber, localRoundNumber].filter((value) => value > 0))
  );

  for (const roundNumber of roundNumberCandidates) {
    const keyedRound = args.persistedResolvedRoundsByKey.get(getSnapshotRoundKey(roundNumber));
    if (keyedRound) return keyedRound;
    const numberedRound = args.resolvedRounds.find((round) => Number(round.round) === roundNumber);
    if (numberedRound) return numberedRound;
  }

  const selectedDate = asText(selectedRound.session_date);
  const timeMatchedRound = args.resolvedRounds.find((round) => {
    const roundDate = asText(round.sessionDate);
    const dateMatches = !selectedDate || !roundDate || selectedDate === roundDate;
    return dateMatches && timesMatch(round.startTime, selectedRound.start_time) && timesMatch(round.endTime, selectedRound.end_time);
  });
  if (timeMatchedRound) return timeMatchedRound;

  const safeGlobalIndex = args.selectedRoundGlobalIndex >= 0 ? args.selectedRoundGlobalIndex : -1;
  if (safeGlobalIndex >= 0 && safeGlobalIndex < args.resolvedRounds.length) return args.resolvedRounds[safeGlobalIndex];

  const safeLocalIndex = args.selectedRoundIndex >= 0 ? args.selectedRoundIndex : -1;
  if (safeLocalIndex >= 0 && safeLocalIndex < args.resolvedRounds.length) return args.resolvedRounds[safeLocalIndex];

  return null;
}

function getRotationRoundDurationMinutes(round: RotationRound) {
  const startMinutes = parseTimeToMinutes(round.start_time);
  const endMinutes = parseTimeToMinutes(round.end_time);
  if (startMinutes === null || endMinutes === null) return null;
  const adjustedEndMinutes = normalizeEndMinutesForRange(startMinutes, endMinutes);
  if (adjustedEndMinutes === null) return null;
  return Math.max(adjustedEndMinutes - startMinutes, 0);
}

function isOvernightSessionGroup<T extends { start_time?: string | null; end_time?: string | null }>(
  sessions: T[]
) {
  const starts = sessions
    .map((session) => parseTimeToMinutes(session.start_time))
    .filter((minutes): minutes is number => minutes !== null);
  if (!starts.length) return false;

  const hasExplicitRollover = sessions.some((session) => {
    const start = parseTimeToMinutes(session.start_time);
    const end = parseTimeToMinutes(session.end_time);
    return start !== null && end !== null && end < start;
  });
  const hasLateAndEarlyStarts =
    starts.some((minutes) => minutes >= 18 * 60) &&
    starts.some((minutes) => minutes < 8 * 60);

  return hasExplicitRollover || hasLateAndEarlyStarts;
}

function getOvernightAwareStartMinutes<T extends { start_time?: string | null }>(
  item: T,
  overnightGroup: boolean
) {
  const start = parseTimeToMinutes(item.start_time);
  if (start === null) return Number.MAX_SAFE_INTEGER;
  return overnightGroup && start < 8 * 60 ? start + MINUTES_PER_DAY : start;
}

function getNormalizedRotationRoundTiming(round: RotationRound, sameDateRounds: RotationRound[]) {
  const rawStartMinutes = parseTimeToMinutes(round.start_time);
  const rawEndMinutes = parseTimeToMinutes(round.end_time);
  if (rawStartMinutes === null || rawEndMinutes === null) return null;

  const overnightGroup = isOvernightSessionGroup(sameDateRounds);
  const startMinutes = getOvernightAwareStartMinutes(round, overnightGroup);
  let endMinutes = normalizeEndMinutesForRange(rawStartMinutes, rawEndMinutes);
  if (startMinutes >= MINUTES_PER_DAY && endMinutes !== null && endMinutes < MINUTES_PER_DAY) {
    endMinutes += MINUTES_PER_DAY;
  }
  if (endMinutes === null || endMinutes <= startMinutes) return null;
  return { startMinutes, endMinutes };
}

function getSameDateRotationRounds(round: RotationRound, rounds: RotationRound[]) {
  const dateKey = asText(round.session_date) || "date-tbd";
  return rounds.filter((candidate) => (asText(candidate.session_date) || "date-tbd") === dateKey);
}

function sortEventSessionsForTimeline(sessions: EventSessionRow[], fallbackYear?: number | null) {
  const groups = sessions.reduce<Map<string, EventSessionRow[]>>((map, session) => {
    const dateKey = normalizeLooseDateToIso(session.session_date, fallbackYear) || asText(session.session_date) || "date-tbd";
    map.set(dateKey, [...(map.get(dateKey) || []), session]);
    return map;
  }, new Map());
  const overnightDateKeys = new Set<string>();
  groups.forEach((dateSessions, dateKey) => {
    if (isOvernightSessionGroup(dateSessions)) overnightDateKeys.add(dateKey);
  });

  return [...sessions].sort((a, b) => {
    const aDate = normalizeLooseDateToIso(a.session_date, fallbackYear) || asText(a.session_date);
    const bDate = normalizeLooseDateToIso(b.session_date, fallbackYear) || asText(b.session_date);
    const dateCompare = aDate.localeCompare(bDate);
    if (dateCompare !== 0) return dateCompare;
    const aDateKey = aDate || "date-tbd";
    const bDateKey = bDate || "date-tbd";
    const aStart = getOvernightAwareStartMinutes(a, overnightDateKeys.has(aDateKey));
    const bStart = getOvernightAwareStartMinutes(b, overnightDateKeys.has(bDateKey));
    if (aStart !== bStart) return aStart - bStart;
    return asText(a.id).localeCompare(asText(b.id));
  });
}

function shouldKeepRotationRound(round: RotationRound, sameDateRounds: RotationRound[]) {
  const hasRooms = round.rooms.length > 0;
  const hasRoomedPeer = sameDateRounds.some((peer) => peer.key !== round.key && peer.rooms.length > 0);

  if (!hasRooms && hasRoomedPeer) {
    return false;
  }

  const durationMinutes = getRotationRoundDurationMinutes(round);
  const hasEncounterPeer = sameDateRounds.some((peer) => {
    if (peer.key === round.key || !peer.rooms.length) return false;
    const peerDuration = getRotationRoundDurationMinutes(peer);
    return peerDuration !== null && peerDuration > 0 && peerDuration <= 120;
  });

  // Imported event/session-wide rows can share a start time with true encounter rounds.
  // Keep those day-wide blocks out of the selectable Rotation Plan so details stay round-scoped.
  if (durationMinutes !== null && durationMinutes > 120 && hasEncounterPeer) {
    return false;
  }

  return true;
}

function buildRotationRounds(sessions: EventSessionRow[]): RotationRound[] {
  const rounds = new Map<string, RotationRound>();

  sessions.forEach((session) => {
    const key = getRotationRoundKeyFromSession(session);

    const existing = rounds.get(key);
    const room = asText(session.room);

    if (existing) {
      if (room && !existing.rooms.includes(room)) existing.rooms.push(room);
      return;
    }

    rounds.set(key, {
      key,
      session_date: session.session_date,
      start_time: session.start_time,
      end_time: session.end_time,
      rooms: room ? [room] : [],
    });
  });

  const sortedRounds = Array.from(rounds.values()).map((round) => ({
    ...round,
    rooms: sortRoomLabelsForDisplay(round.rooms),
  }));
  const roundsByDate = sortedRounds.reduce<Map<string, RotationRound[]>>((map, round) => {
    const dateKey = asText(round.session_date) || "date-tbd";
    map.set(dateKey, [...(map.get(dateKey) || []), round]);
    return map;
  }, new Map());
  const filteredRounds = sortedRounds.filter((round) => {
    const dateKey = asText(round.session_date) || "date-tbd";
    return shouldKeepRotationRound(round, roundsByDate.get(dateKey) || sortedRounds);
  });
  const displayRounds = filteredRounds.length ? filteredRounds : sortedRounds;
  const overnightDateKeys = new Set<string>();
  roundsByDate.forEach((dateRounds, dateKey) => {
    if (isOvernightSessionGroup(dateRounds)) overnightDateKeys.add(dateKey);
  });

  return displayRounds.sort((a, b) => {
    const dateCompare = asText(a.session_date).localeCompare(asText(b.session_date));
    if (dateCompare !== 0) return dateCompare;
    const dateKey = asText(a.session_date) || "date-tbd";
    const aStart = getOvernightAwareStartMinutes(a, overnightDateKeys.has(dateKey));
    const bStart = getOvernightAwareStartMinutes(b, overnightDateKeys.has(dateKey));
    if (aStart !== bStart) return aStart - bStart;
    const startCompare = asText(a.start_time).localeCompare(asText(b.start_time));
    if (startCompare !== 0) return startCompare;
    const aDuration = getRotationRoundDurationMinutes(a);
    const bDuration = getRotationRoundDurationMinutes(b);
    if (aDuration !== null && bDuration !== null && aDuration !== bDuration) return aDuration - bDuration;
    return b.rooms.length - a.rooms.length;
  });
}

function capRotationRounds(rounds: RotationRound[], maxRounds: number) {
  if (maxRounds <= 0 || rounds.length <= maxRounds) return rounds;
  return rounds.slice(0, maxRounds);
}

function buildRotationRoundsFromScheduleDraft(
  draft: ScheduleBuilderPreviewDraft | null,
  roundCount: number,
  dateText: string | null | undefined,
  endTimeText?: string | null,
  fallbackYear?: number | null
) {
  const startMinutes = parseTimeToMinutes(draft?.startTime);
  const normalizedEndMinutes = parseTimeToMinutes(endTimeText);
  const normalizedEnd = normalizedEndMinutes === null || startMinutes === null ? null : normalizeEndMinutesForRange(startMinutes, normalizedEndMinutes);
  if (!draft || startMinutes === null || roundCount <= 0) return [] as RotationRound[];

  const encounterMinutes = Math.max(1, parsePositiveInteger(draft.encounterMinutes, 20));
  const recurringBlocks = draft.dayBlocks.filter((block) => {
    const placement = asText(block.placement).toLowerCase();
    return (
      parsePositiveInteger(block.durationMinutes, 0) > 0 &&
      (placement === "after_each_rotation" || placement === "after_every_x_rotations")
    );
  });
  const roomNames = [
    ...Array.from({ length: parsePositiveInteger(draft.examRoomCount, 0) }, (_, index) => `Exam ${index + 1}`),
    ...Array.from({ length: parsePositiveInteger(draft.flexRoomCount, 0) }, (_, index) => `Flex ${index + 1}`),
  ];
  const sessionDate = normalizeLooseDateToIso(dateText, fallbackYear) || asText(dateText) || null;
  let cursor = startMinutes;

  return (() => {
    const rounds: RotationRound[] = [];

    for (let index = 0; index < roundCount; index += 1) {
      const roundNumber = index + 1;
      const recurringMinutes = recurringBlocks.reduce((sum, block) => {
        const placement = asText(block.placement).toLowerCase();
        if (placement === "after_every_x_rotations") {
          const interval = Math.max(1, parsePositiveInteger(block.placementInterval, 2));
          if (roundNumber % interval !== 0) return sum;
        }
        return sum + parsePositiveInteger(block.durationMinutes, 0);
      }, 0);
      const duration = Math.max(1, encounterMinutes + recurringMinutes);
      const roundEnd = cursor + duration;
      if (normalizedEnd !== null && roundEnd > normalizedEnd) {
        return rounds;
      }
      const round: RotationRound = {
        key: `completed-snapshot-round-${roundNumber}`,
        session_date: sessionDate,
        start_time: formatDisplayTimeFromMinutes(cursor),
        end_time: formatDisplayTimeFromMinutes(roundEnd),
        rooms: roomNames,
      };
      rounds.push(round);
      cursor += duration;
    }
    return rounds;
  })();
}

function getCanonicalNurs421RoomSpName(eventId: string | null | undefined, slotIndex: number) {
  if (eventId !== "85224c71-8b22-4b0b-960d-5e8dfd8d1515") return "";
  return [
    "Yvette Bedgood",
    "William Ochester",
    "Lee Fishman",
    "Jennifer Smith",
    "Celeste Montgomery",
    "Gene D’Alessandro",
  ][slotIndex] || "";
}

function formatRotationRoundLabel(
  round: RotationRound,
  fallbackYear?: number | null,
  roomCountOverride?: number | null
) {
  const date = formatSessionDate(round.session_date, fallbackYear);
  const time =
    round.start_time && round.end_time
      ? `${formatDisplayTime(round.start_time)} - ${formatDisplayTime(round.end_time)}`
      : formatDisplayTime(round.start_time || round.end_time);

  const roomCount = typeof roomCountOverride === "number" ? roomCountOverride : round.rooms.length;
  const roomText = roomCount ? `${roomCount} room${roomCount === 1 ? "" : "s"}` : "Rooms TBD";

  return [date, time, roomText].filter(Boolean).join(" · ");
}

function getRoundCompanionAudience(label: string): RotationCompanionView[] {
  const normalized = asText(label).toLowerCase();
  if (normalized.includes("soap")) return ["student", "operations"];
  if (normalized.includes("checklist")) return ["sp", "operations"];
  if (normalized.includes("feedback") || normalized.includes("debrief")) return ["student", "sp", "operations"];
  if (normalized.includes("break") || normalized.includes("lunch") || normalized.includes("transition")) {
    return ["student", "sp", "operations"];
  }
  return ["operations"];
}

function getScheduleBuilderStorageKey(eventId?: string) {
  return `cfsp:schedule-builder:${eventId || "global"}`;
}

function parseScheduleBuilderDay(raw: string | null) {
  const parsed = Number.parseInt(raw || "", 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : null;
}

function getRotationCommandSurfaceStorageKey(eventId?: string) {
  return `cfsp:rotation-command-surface:${eventId || "global"}`;
}

function getTacticalRoomBoardStorageKey(eventId?: string) {
  return `cfsp:tactical-room-board:${eventId || "global"}`;
}

function getEventCommandDockPanelStorageKey(eventId?: string) {
  return `cfsp:event-command-dock-panels:${eventId || "global"}`;
}

function parsePositiveInteger(value: unknown, fallback = 0) {
  const parsed = Number(asText(value));
  if (!Number.isFinite(parsed)) return fallback;
  return Math.max(0, Math.floor(parsed));
}

function normalizeTextArray(value: unknown) {
  return normalizeLearnerNames(value);
}

function hasMeaningfulTrainingValue(value: unknown) {
  const normalized = asText(value).toLowerCase();
  if (!normalized) return false;
  return !["not assigned", "none", "n/a", "na", "unknown", "unassigned", "tbd"].includes(normalized);
}

const EVENT_FAMILY_TRAINING_MERGE_KEYS = [
  "training_required",
  "training_ownership",
  "training_scheduling_status",
  "training_date",
  "training_start_time",
  "training_end_time",
  "preferred_training_date",
  "preferred_training_time",
  "preferred_training_end_time",
  "faculty_availability_unknown",
  "training_zoom_required",
  "training_zoom_link",
  "training_recording_planned",
  "faculty_training_coordination_requested",
  "faculty_training_coordination_status",
  "faculty_training_coordination_requested_at",
  "faculty_request_sent_at",
  "zoom_url",
  "training_password",
  "training_recording_url",
  "training_recording_status",
  "training_attendance_status",
  "recording_url",
  "recording_status",
  "case_name",
  "case_file_url",
  "case_file_name",
  "case_file_storage_path",
  "case_file_uploaded_at",
  "case_file_uploaded_by",
  "case_files",
  "case_manager_cases",
  "case_count",
  "case_roles_per_case",
  "case_rotation_required",
  "case_fixed_rooms",
  "case_extra_rooms_mode",
  "doorsign_url",
  "doorsign_file_url",
  "doorsign_file_name",
  "doorsign_storage_path",
  "doorsign_uploaded_at",
  "doorsign_uploaded_by",
  "additional_materials",
  "supplemental_doc_url",
  "supplemental_doc_name",
  "supplemental_doc_storage_path",
  "supplemental_doc_uploaded_at",
  "supplemental_doc_uploaded_by",
  "faculty_names",
  "faculty_program",
  "faculty_email",
  "faculty_phone",
  "sim_contact",
  "contact_internal_notes",
  "training_notes",
] as const satisfies readonly (keyof TrainingEventMetadata)[];

function mergeEventFamilyTrainingMetadata(
  primary: TrainingEventMetadata,
  relatedNodes: RelatedOperationalEventNode[]
) {
  const merged = { ...primary };
  const allowedRelatedMetadata = relatedNodes
    .filter((node) => {
      if (node.isConfirmed) return true;
      const confidence = asText(node.match_confidence).toLowerCase();
      return confidence === "exact_course" || confidence === "title_family" || confidence === "source_batch";
    })
    .map((node) => node.trainingMetadata)
    .filter((metadata): metadata is TrainingEventMetadata => Boolean(metadata));

  if (!allowedRelatedMetadata.length) return merged;

  EVENT_FAMILY_TRAINING_MERGE_KEYS.forEach((key) => {
    if (hasMeaningfulTrainingValue(merged[key])) return;
    const source = allowedRelatedMetadata.find((metadata) => hasMeaningfulTrainingValue(metadata[key]));
    if (source) merged[key] = source[key];
  });

  return merged;
}

const UNASSIGNED_LEARNER_ROOM_LABEL = "No learner assigned for this room/round";
const LEGACY_UNASSIGNED_LEARNER_LABEL = "Learner not assigned";

function parseScheduleLearnerRosterMetadata(value: unknown) {
  const text = asText(value);
  if (!text) return [] as string[];

  const candidates = [text];
  try {
    candidates.unshift(decodeURIComponent(text));
  } catch {
    // Legacy metadata may already be plain JSON or plain text.
  }

  for (const candidate of candidates) {
    try {
      const parsed = JSON.parse(candidate);
      const roster = normalizeTextArray(parsed);
      if (roster.length) return roster;
    } catch {
      // Fall through to line/comma parsing for older hand-authored metadata.
    }
  }

  return text
    .split(/\r?\n|,/)
    .map((item) => normalizeLearnerName(item))
    .filter(Boolean);
}

function getLearnerRoomAssignmentLabel(learnerLabels: string[]) {
  const labels = normalizeLearnerNames(learnerLabels);
  return labels.length ? labels.join(", ") : UNASSIGNED_LEARNER_ROOM_LABEL;
}

function parseScheduleRoomAdjustments(value: unknown) {
  const text = asText(value);
  const roundsByNumber: ParsedScheduleRoomAdjustments = new Map();
  if (!text) return roundsByNumber;

  try {
    const parsed = JSON.parse(text) as {
      rounds?: Array<{
        round?: unknown;
        slots?: Array<{
          slotIndex?: unknown;
          learnerLabels?: unknown;
          manualOverride?: unknown;
          source?: unknown;
          stationStatus?: unknown;
          isBackupStation?: unknown;
          roomName?: unknown;
          spName?: unknown;
          backupSpName?: unknown;
          caseLabel?: unknown;
          roleId?: unknown;
          roleLabel?: unknown;
          notes?: unknown;
        }>;
      }>;
    };
    if (!parsed || typeof parsed !== "object") return roundsByNumber;
    (parsed.rounds || []).forEach((roundEntry) => {
      const roundNumber = parsePositiveInteger(roundEntry?.round, 0);
      if (!roundNumber) return;
      const slots = (roundEntry.slots || [])
        .map((slotEntry) => {
          const slotIndex = Number(slotEntry?.slotIndex);
          if (!Number.isFinite(slotIndex) || slotIndex < 0) return null;
          const learnerLabels = normalizeLearnerNames(slotEntry?.learnerLabels || []);
          const manualOverride = parseBooleanValue(slotEntry?.manualOverride, false);
          const source = normalizeDisplayText(slotEntry?.source);
          const stationStatus = normalizeScheduleStationStatus(slotEntry?.stationStatus);
          const isBackupStation = parseBooleanValue(slotEntry?.isBackupStation, false);
          const roomName = normalizeDisplayText(slotEntry?.roomName);
          const spName = normalizeDisplayText(slotEntry?.spName);
          const backupSpName = normalizeDisplayText(slotEntry?.backupSpName);
          const caseLabel = normalizeDisplayText(slotEntry?.caseLabel);
          const roleId = normalizeDisplayText(slotEntry?.roleId);
          const roleLabel = normalizeDisplayText(slotEntry?.roleLabel);
          const notes = normalizeDisplayText(slotEntry?.notes);
          if (!learnerLabels.length && !manualOverride && !source && !stationStatus && !isBackupStation && !roomName && !spName && !backupSpName && !caseLabel && !roleId && !roleLabel && !notes) return null;
          return {
            slotIndex,
            learnerLabels,
            ...(manualOverride ? { manualOverride: true } : {}),
            ...(source ? { source } : {}),
            ...(stationStatus ? { stationStatus } : {}),
            ...(isBackupStation ? { isBackupStation: true } : {}),
            ...(roomName ? { roomName } : {}),
            ...(spName ? { spName } : {}),
            ...(backupSpName ? { backupSpName } : {}),
            ...(caseLabel ? { caseLabel } : {}),
            ...(roleId ? { roleId } : {}),
            ...(roleLabel ? { roleLabel } : {}),
            ...(notes ? { notes } : {}),
          } satisfies ScheduleRoomAdjustmentSlot;
        })
        .filter(Boolean) as ScheduleRoomAdjustmentSlot[];
      if (slots.length) roundsByNumber.set(roundNumber, slots);
    });
  } catch {
    return new Map();
  }

  return roundsByNumber;
}

function serializeScheduleRoomAdjustments(value: ParsedScheduleRoomAdjustments) {
  return JSON.stringify({
    v: 1,
    rounds: Array.from(value.entries())
      .sort((a, b) => a[0] - b[0])
      .map(([round, slots]) => ({
        round,
        slots: slots
          .slice()
          .sort((a, b) => a.slotIndex - b.slotIndex)
          .map((slot) => ({
            slotIndex: slot.slotIndex,
            learnerLabels: normalizeLearnerNames(slot.learnerLabels || []),
            ...(slot.manualOverride ? { manualOverride: true } : {}),
            ...(normalizeDisplayText(slot.source) ? { source: normalizeDisplayText(slot.source) } : {}),
            ...(normalizeScheduleStationStatus(slot.stationStatus) ? { stationStatus: normalizeScheduleStationStatus(slot.stationStatus) } : {}),
            ...(slot.isBackupStation ? { isBackupStation: true } : {}),
            ...(normalizeDisplayText(slot.roomName) ? { roomName: normalizeDisplayText(slot.roomName) } : {}),
            ...(normalizeDisplayText(slot.spName) ? { spName: normalizeDisplayText(slot.spName) } : {}),
            ...(normalizeDisplayText(slot.backupSpName) ? { backupSpName: normalizeDisplayText(slot.backupSpName) } : {}),
            ...(normalizeDisplayText(slot.caseLabel) ? { caseLabel: normalizeDisplayText(slot.caseLabel) } : {}),
            ...(normalizeDisplayText(slot.roleId) ? { roleId: normalizeDisplayText(slot.roleId) } : {}),
            ...(normalizeDisplayText(slot.roleLabel) ? { roleLabel: normalizeDisplayText(slot.roleLabel) } : {}),
            ...(normalizeDisplayText(slot.notes) ? { notes: normalizeDisplayText(slot.notes) } : {}),
          })),
      }))
      .filter((entry) =>
        entry.slots.some((slot) =>
          slot.learnerLabels.length ||
          slot.manualOverride ||
          normalizeDisplayText(slot.source) ||
          normalizeScheduleStationStatus(slot.stationStatus) ||
          slot.isBackupStation ||
          normalizeDisplayText(slot.roomName) ||
          normalizeDisplayText(slot.spName) ||
          normalizeDisplayText(slot.backupSpName) ||
          normalizeDisplayText(slot.caseLabel) ||
          normalizeDisplayText(slot.roleId) ||
          normalizeDisplayText(slot.roleLabel) ||
          normalizeDisplayText(slot.notes)
        )
      ),
  });
}

function normalizeScheduleStationStatus(value: unknown): ScheduleStationStatus | "" {
  const normalized = normalizeDisplayText(value).toLowerCase();
  if (normalized === "active") return "active";
  if (normalized === "backup" || normalized === "standby") return "backup";
  if (normalized === "inactive" || normalized === "empty") return "inactive";
  return "";
}

function isExplicitManualRoomEdit(slot?: Partial<ScheduleRoomAdjustmentSlot> | null) {
  return Boolean(slot?.manualOverride || normalizeDisplayText(slot?.source) === "manual-room-edit");
}

function isScheduleBackupStation(slot?: Partial<ScheduleRoomAdjustmentSlot> | null) {
  return Boolean(slot?.isBackupStation || normalizeScheduleStationStatus(slot?.stationStatus) === "backup");
}

function upsertScheduleRoomAdjustmentSlot(
  adjustments: ParsedScheduleRoomAdjustments,
  roundNumber: number,
  slotIndex: number,
  partial: Partial<ScheduleRoomAdjustmentSlot>
) {
  const next = new Map(adjustments);
  const currentSlots = next.get(roundNumber)?.slice() || [];
  const existing = currentSlots.find((slot) => slot.slotIndex === slotIndex) || {
    slotIndex,
    learnerLabels: [],
  };
  const merged: ScheduleRoomAdjustmentSlot = {
    ...existing,
    ...partial,
    slotIndex,
    manualOverride:
      partial.manualOverride !== undefined
        ? Boolean(partial.manualOverride)
        : partial.learnerLabels !== undefined
        ? true
        : Boolean(existing.manualOverride),
    learnerLabels:
      partial.learnerLabels !== undefined
        ? normalizeLearnerNames(partial.learnerLabels)
        : normalizeLearnerNames(existing.learnerLabels || []),
  };
  const filtered = currentSlots.filter((slot) => slot.slotIndex !== slotIndex);
  if (
    merged.learnerLabels.length ||
    merged.manualOverride ||
    asText(merged.roomName) ||
    asText(merged.source) ||
    asText(merged.stationStatus) ||
    Boolean(merged.isBackupStation) ||
    asText(merged.spName) ||
    asText(merged.backupSpName) ||
    asText(merged.caseLabel) ||
    asText(merged.roleId) ||
    asText(merged.roleLabel) ||
    asText(merged.notes)
  ) {
    filtered.push(merged);
  }
  if (filtered.length) next.set(roundNumber, filtered);
  else next.delete(roundNumber);
  return next;
}

function isAssignedLearnerRoomLabel(label: unknown) {
  const text = asText(label);
  if (!text) return false;
  const normalized = text.toLowerCase();
  return (
    normalized !== LEGACY_UNASSIGNED_LEARNER_LABEL.toLowerCase() &&
    normalized !== UNASSIGNED_LEARNER_ROOM_LABEL.toLowerCase() &&
    normalized !== "overflow / standby"
  );
}

function getResolvedRoundLearnerLabels(args: {
  learnerRoster: string[];
  roomCapacity: number;
  roundIndex: number;
  slotIndex: number;
  roomSlotCount: number;
  activeCaseCount: number;
  isMultiCaseMode: boolean;
  isVirtualEvent: boolean;
}) {
  const roster = normalizeLearnerNames(args.learnerRoster);
  const safeRoomCapacity = Math.max(args.roomCapacity, 1);
  const safeRoomSlotCount = Math.max(args.roomSlotCount, 1);

  if (!roster.length) return [] as string[];

  if (args.isMultiCaseMode && args.activeCaseCount > 1) {
    const learnerGroups: Array<{ labels: string[] }> = [];
    for (let index = 0; index < roster.length; index += safeRoomCapacity) {
      learnerGroups.push({ labels: roster.slice(index, index + safeRoomCapacity) });
    }

    const activeRoomCount = Math.min(Math.max(args.activeCaseCount, 1), safeRoomSlotCount);
    const groupCount = learnerGroups.length;
    if (!activeRoomCount || !groupCount || args.slotIndex >= activeRoomCount) return [];

    const rotationIndex = args.roundIndex % Math.max(args.activeCaseCount, groupCount, 1);
    const effectiveSlotIndex = args.isVirtualEvent ? args.slotIndex : args.slotIndex;
    let groupIndex: number | null = null;
    if (groupCount >= activeRoomCount) {
      groupIndex = (rotationIndex + effectiveSlotIndex) % groupCount;
    } else {
      const candidateGroup = args.isVirtualEvent
        ? (rotationIndex + effectiveSlotIndex) % activeRoomCount
        : ((effectiveSlotIndex - rotationIndex) % activeRoomCount + activeRoomCount) % activeRoomCount;
      groupIndex = candidateGroup < groupCount ? candidateGroup : null;
    }

    return groupIndex === null ? [] : learnerGroups[groupIndex]?.labels || [];
  }

  const firstLearnerIndex = args.roundIndex * safeRoomSlotCount * safeRoomCapacity + args.slotIndex * safeRoomCapacity;
  return Array.from({ length: safeRoomCapacity }, (_, learnerOffset) => roster[firstLearnerIndex + learnerOffset] || "")
    .filter(Boolean);
}

function normalizeScheduleBuilderDayBlocks(value: unknown) {
  if (!Array.isArray(value)) return [] as ScheduleBuilderPreviewDayBlock[];

  return value
    .map((item, index) => {
      const record = item && typeof item === "object" ? (item as Record<string, unknown>) : {};
      const label = asText(record.label) || asText(record.type) || "Schedule Block";
      return {
        id: asText(record.id) || `schedule-block-${index}`,
        type: asText(record.type),
        label,
        durationMinutes: asText(record.durationMinutes),
        placement: asText(record.placement) || "after_each_rotation",
        placementInterval: asText(record.placementInterval) || "2",
        specificTime: asText(record.specificTime),
        visibleTo: asText(record.visibleTo) || "both",
      };
    })
    .filter((block) => Boolean(block.label));
}

function parseBooleanValue(value: unknown, fallback = false) {
  if (typeof value === "boolean") return value;
  const text = asText(value).toLowerCase();
  if (text === "true" || text === "1" || text === "yes") return true;
  if (text === "false" || text === "0" || text === "no") return false;
  return fallback;
}

function parseScheduleBuilderPreviewDraft(value: string | null) {
  if (!value) return null;

  try {
    const parsed = JSON.parse(value) as Record<string, unknown>;
    if (!parsed || typeof parsed !== "object") return null;
    const resolvedRounds = Array.isArray(parsed.resolvedRounds)
      ? parsed.resolvedRounds
          .map((round, index) => {
            const record = round && typeof round === "object" ? (round as Record<string, unknown>) : {};
            const roomSlots = Array.isArray(record.roomSlots)
              ? record.roomSlots
                  .map((slot) => {
                    const slotRecord = slot && typeof slot === "object" ? (slot as Record<string, unknown>) : {};
                    return {
                      roomName: asText(slotRecord.roomName),
                      learnerLabels: normalizeTextArray(slotRecord.learnerLabels),
                      assignedSpName: asText(slotRecord.assignedSpName),
                      backupSpName: asText(slotRecord.backupSpName),
                      caseLabel: asText(slotRecord.caseLabel),
                      roleId: asText(slotRecord.roleId),
                      roleLabel: asText(slotRecord.roleLabel),
                      notes: asText(slotRecord.notes),
                    } satisfies ScheduleBuilderPreviewResolvedRoomSlot;
                  })
                  .filter(
                    (slot) =>
                      Boolean(
                        slot.roomName ||
                          slot.learnerLabels.length ||
                          slot.assignedSpName ||
                          slot.backupSpName ||
                          slot.caseLabel ||
                          slot.roleLabel ||
                          slot.notes
                      )
                  )
              : [];
            return {
              round: Math.max(1, parsePositiveInteger(record.round, index + 1)),
              sessionDate: asText(record.sessionDate) || asText(parsed.eventDate),
              startTime: asText(record.startTime),
              endTime: asText(record.endTime),
              roomSlots,
            } satisfies ScheduleBuilderPreviewResolvedRound;
          })
          .filter((round) => round.roomSlots.length > 0 || Boolean(round.startTime || round.endTime))
      : [];
    const derivedRoundCount = resolvedRounds.length;
    const derivedRoomCount = resolvedRounds.reduce((maxCount, round) => Math.max(maxCount, round.roomSlots.length), 0);

    return {
      learnerFileName: asText(parsed.learnerFileName),
      uploadedLearners: normalizeTextArray(parsed.uploadedLearners),
      originalUploadedLearners: normalizeTextArray(parsed.originalUploadedLearners),
      roundCount: asText(parsed.roundCount),
      examRoomCount: asText(parsed.examRoomCount),
      flexRoomCount: asText(parsed.flexRoomCount),
      maxPairsPerFlexRoom: asText(parsed.maxPairsPerFlexRoom),
      startTime: asText(parsed.startTime),
      staffArrivalTime: asText(parsed.staffArrivalTime),
      spArrivalTime: asText(parsed.spArrivalTime),
      facultyArrivalTime: asText(parsed.facultyArrivalTime),
      roomSetupMinutes: asText(parsed.roomSetupMinutes),
      studentPrebriefMinutes: asText(parsed.studentPrebriefMinutes),
      spPrebriefMinutes: asText(parsed.spPrebriefMinutes),
      facultyPrebriefMinutes: asText(parsed.facultyPrebriefMinutes),
      encounterMinutes: asText(parsed.encounterMinutes),
      roomCapacity: asText(parsed.roomCapacity),
      manualRoundOverride: parseBooleanValue(parsed.manualRoundOverride, false),
      dayBlocks: normalizeScheduleBuilderDayBlocks(parsed.dayBlocks),
      snapshotVersion: parsePositiveInteger(parsed.snapshotVersion, 0) || undefined,
      scheduleStatus: asText(parsed.scheduleStatus),
      scheduleRoundCount: Math.max(derivedRoundCount, parsePositiveInteger(parsed.scheduleRoundCount, 0)),
      scheduleRoomCount: Math.max(derivedRoomCount, parsePositiveInteger(parsed.scheduleRoomCount, 0)),
      scheduleRoomCapacity: Math.max(0, parsePositiveInteger(parsed.scheduleRoomCapacity, 0)),
      scheduleLearnerRoster: normalizeTextArray(parsed.scheduleLearnerRoster),
      eventDate: asText(parsed.eventDate),
      resolvedRounds,
      savedAt: asText(parsed.savedAt),
    } satisfies ScheduleBuilderPreviewDraft;
  } catch {
    return null;
  }
}

function parseCompletedScheduleBuilderSnapshot(value: unknown) {
  const text = asText(value);
  if (!text) return null;

  const candidates = [text];
  try {
    candidates.unshift(decodeURIComponent(text));
  } catch {
    // Completed snapshots are stored URL-encoded; keep plain JSON as a legacy fallback.
  }

  for (const candidate of candidates) {
    const parsed = parseScheduleBuilderPreviewDraft(candidate);
    if (parsed?.startTime) return parsed;
  }

  return null;
}

function parseScheduleBuilderPreviewDays(raw: string | null | undefined) {
  const text = asText(raw);
  if (!text) return new Map<number, ScheduleBuilderPreviewDraft>();

  try {
    const parsed = JSON.parse(text) as Record<string, string>;
    if (!parsed || typeof parsed !== "object") return new Map<number, ScheduleBuilderPreviewDraft>();

    const output = new Map<number, ScheduleBuilderPreviewDraft>();
    Object.entries(parsed).forEach(([rawKey, encodedSnapshot]) => {
      const day = Number.parseInt(rawKey, 10);
      if (!Number.isFinite(day) || day <= 0 || typeof encodedSnapshot !== "string") return;
      const snapshot = parseCompletedScheduleBuilderSnapshot(encodedSnapshot);
      if (snapshot) output.set(day, snapshot);
    });

    return output;
  } catch {
    return new Map<number, ScheduleBuilderPreviewDraft>();
  }
}

function resolveScheduleBuilderPreviewSnapshot(
  metadata: Partial<TrainingEventMetadata> | null | undefined,
  options?: { scheduleDay?: number | null; localStorageSnapshot?: string | null }
) {
  const effectiveDay = options?.scheduleDay && options.scheduleDay > 0 ? options.scheduleDay : 1;
  const serverDaySnapshots = parseScheduleBuilderPreviewDays(asText(metadata?.schedule_builder_days));
  const serverSnapshotFromDay = serverDaySnapshots.get(effectiveDay) || null;
  const inheritedDaySnapshot =
    effectiveDay > 1 && serverDaySnapshots.has(effectiveDay - 1)
      ? serverDaySnapshots.get(effectiveDay - 1) || null
      : null;
  const fallbackLegacySnapshot = parseCompletedScheduleBuilderSnapshot(metadata?.schedule_builder_snapshot);
  const localSnapshot = options?.localStorageSnapshot
    ? parseScheduleBuilderPreviewDraft(options.localStorageSnapshot)
    : null;

  const getSnapshotRoundCount = (snapshot: ScheduleBuilderPreviewDraft | null) =>
    Math.max(
      snapshot?.resolvedRounds?.length || 0,
      snapshot?.scheduleRoundCount || 0,
      parsePositiveInteger(snapshot?.roundCount, 0)
    );

  const orderedServerSnapshots = [
    serverSnapshotFromDay,
    inheritedDaySnapshot,
    fallbackLegacySnapshot,
  ].filter(Boolean) as ScheduleBuilderPreviewDraft[];

  const bestCompletedServerSnapshot =
    orderedServerSnapshots.length > 0
      ? [...orderedServerSnapshots].sort(
          (a, b) => getSnapshotRoundCount(b) - getSnapshotRoundCount(a)
        )[0]
      : null;

  const serverSnapshot = serverSnapshotFromDay || inheritedDaySnapshot || fallbackLegacySnapshot;
  const completedSnapshot =
    asText(metadata?.schedule_status).toLowerCase() === "complete"
      ? bestCompletedServerSnapshot || serverSnapshot
      : null;

  return {
    effectiveDay,
    serverDaySnapshots,
    serverSnapshotFromDay,
    inheritedDaySnapshot,
    fallbackLegacySnapshot,
    serverSnapshot,
    completedSnapshot,
    draft: completedSnapshot || serverSnapshot || localSnapshot,
  };
}

function getScheduleBuilderBlockAudience(block: ScheduleBuilderPreviewDayBlock): RotationCompanionView[] {
  const visibleTo = asText(block.visibleTo).toLowerCase();
  const labelAudience = getRoundCompanionAudience(block.label);
  const audiences = new Set<RotationCompanionView>();

  if (visibleTo === "operations") {
    audiences.add("operations");
  } else if (visibleTo === "student") {
    audiences.add("student");
  } else {
    audiences.add("student");
    audiences.add("operations");
  }

  if (visibleTo !== "student" && labelAudience.includes("sp")) {
    audiences.add("sp");
  }
  if (labelAudience.includes("operations")) {
    audiences.add("operations");
  }

  return Array.from(audiences);
}

function shouldShowScheduleBuilderBlockForRound(
  block: ScheduleBuilderPreviewDayBlock,
  roundIndex: number,
  totalRounds: number,
  selectedRound: RotationRound
) {
  const placement = asText(block.placement).toLowerCase();
  if (placement === "after_each_rotation") return true;
  if (placement === "after_every_x_rotations") {
    const interval = Math.max(1, parsePositiveInteger(block.placementInterval, 2));
    return (roundIndex + 1) % interval === 0;
  }
  if (placement === "before_rotations") return roundIndex === 0;
  if (placement === "after_rotations") return roundIndex === totalRounds - 1;
  if (placement === "specific_time") {
    const specificMinutes = parseTimeToMinutes(block.specificTime);
    const startMinutes = parseTimeToMinutes(selectedRound.start_time);
    const endMinutes = parseTimeToMinutes(selectedRound.end_time);
    if (specificMinutes === null || startMinutes === null || endMinutes === null) return false;
    return specificMinutes >= startMinutes && specificMinutes <= endMinutes;
  }
  return true;
}

function formatScheduleBuilderBlockDetail(block: ScheduleBuilderPreviewDayBlock) {
  const duration = parsePositiveInteger(block.durationMinutes, 0);
  const placement = asText(block.placement).replace(/_/g, " ");
  const durationLabel = duration ? `${duration} minute${duration === 1 ? "" : "s"}` : "";
  if (block.specificTime) {
    return [formatDisplayTime(block.specificTime) || block.specificTime, durationLabel].filter(Boolean).join(" · ");
  }
  return [durationLabel, placement].filter(Boolean).join(" · ") || "Schedule block";
}

function formatLiveFlowDurationLabel(durationMinutes: number) {
  const minutes = Math.max(0, Math.round(durationMinutes));
  return `${minutes} minute${minutes === 1 ? "" : "s"}`;
}

function normalizeLiveFlowBlockLabel(label: string, type?: string) {
  const rawLabel = asText(label);
  const normalized = `${asText(type)} ${rawLabel}`.toLowerCase();

  if (/soap/.test(normalized)) return "SOAP Notes";
  if (/checklist/.test(normalized)) return "Checklist";
  if (/feedback/.test(normalized)) return "Feedback";
  if (/debrief/.test(normalized)) return "Debrief";
  if (/pre[\s-]?brief|orientation|briefing/.test(normalized)) return "Prebrief";
  if (/lunch/.test(normalized)) return "Lunch";
  if (/break/.test(normalized)) return "Break";
  if (/transition|turnover|reset/.test(normalized)) return "Transition";
  if (/encounter|rotation|case/.test(normalized)) return "Encounter";
  if (/setup/.test(normalized)) return "Setup";

  return rawLabel.replace(/\s+/g, " ") || "Event Block";
}

function getLiveFlowTone(label: string, type?: string): LiveFlowTone {
  const normalized = `${asText(type)} ${asText(label)}`.toLowerCase();
  if (/encounter|rotation|case/.test(normalized)) return "rotation";
  if (/transition|turnover|reset/.test(normalized)) return "transition";
  if (/break|lunch/.test(normalized)) return "break";
  return "support";
}

function getLiveFlowPlacementNote(block: ScheduleBuilderPreviewDayBlock) {
  const placement = asText(block.placement).toLowerCase();
  if (placement === "before_rotations") return "Before encounters";
  if (placement === "after_rotations") return "After final encounter";
  if (placement === "specific_time") return "Scheduled time";
  if (placement === "after_every_x_rotations") {
    const interval = Math.max(1, parsePositiveInteger(block.placementInterval, 2));
    return `Every ${interval} encounters`;
  }
  if (placement === "after_each_rotation") return "Between encounters";
  return "";
}

function getFallbackLiveFlowLabel(gapMinutes: number, notesText: string) {
  if (gapMinutes >= 40) return "Lunch";
  if (/soap/i.test(notesText) && gapMinutes >= 10) return "SOAP Notes";
  if (/checklist/i.test(notesText) && gapMinutes >= 5) return "Checklist";
  if (gapMinutes >= 15) return "Break";
  return "Transition";
}
function toTimeInputValue(value?: string | null) {
  const trimmed = asText(value);
  if (!trimmed) return "";
  const minutes = parseTimeToMinutes(trimmed);
  if (minutes === null) return trimmed.slice(0, 5);
  const hours = Math.floor(minutes / 60);
  const mins = minutes % 60;
  return `${String(hours).padStart(2, "0")}:${String(mins).padStart(2, "0")}`;
}

function getSessionEditorStateFromStructuredSessions(
  sessions: EventSessionRow[],
  eventDateText?: string | null
): SessionEditorState {
  const primarySession = sessions[0];
  return {
    session_date:
      asText(primarySession?.session_date) ||
      normalizeLooseDateToIso(eventDateText) ||
      "",
    start_time: toTimeInputValue(primarySession?.start_time),
    end_time: toTimeInputValue(primarySession?.end_time),
  };
}

function getEventDetailsSessionEditorState(
  sessions: EventSessionRow[],
  eventDateText: string | null | undefined,
  metadata: TrainingEventMetadata
): SessionEditorState {
  const structuredSessionFallback = getSessionEditorStateFromStructuredSessions(sessions, eventDateText);

  return {
    session_date:
      normalizeLooseDateToIso(metadata.event_session_date) ||
      structuredSessionFallback.session_date,
    start_time: toTimeInputValue(metadata.event_start_time || structuredSessionFallback.start_time),
    // Event Details owns this value. Do not derive it from selected rotation rounds,
    // imported schedule blocks, or preferred training windows after it has been saved.
    end_time: toTimeInputValue(metadata.event_end_time || structuredSessionFallback.end_time),
  };
}

function toStoredTimeValue(value: string) {
  const trimmed = value.trim();
  if (!trimmed) return null;
  return trimmed.length === 5 ? `${trimmed}:00` : trimmed;
}

function formatTimeWindowLabel(start?: string | null, end?: string | null) {
  const startText = asText(start);
  const endText = asText(end);
  if (startText && endText) return `${formatDisplayTime(startText)} - ${formatDisplayTime(endText)}`;
  return formatDisplayTime(startText || endText);
}

