function buildMailtoHref(args: {
  to?: string;
  cc?: string[];
  bcc: string[];
  subject: string;
  body: string;
}) {
  const parts: string[] = [];
  if (args.cc?.length) parts.push(`cc=${encodeURIComponent(args.cc.join(","))}`);
  if (args.bcc.length) parts.push(`bcc=${encodeURIComponent(args.bcc.join(","))}`);
  parts.push(`subject=${encodeURIComponent(normalizeEmailPlainText(args.subject))}`);
  parts.push(`body=${encodeURIComponent(normalizeEmailPlainText(args.body))}`);
  return `mailto:${encodeURIComponent(args.to || "")}?${parts.join("&")}`;
}

function hasNotesLine(notes: string | null | undefined, pattern: RegExp) {
  return pattern.test(asText(notes));
}

async function parseApiError(response: Response) {
  try {
    const body = await response.json();
    return body?.error || `${response.status} ${response.statusText}`;
  } catch {
    return `${response.status} ${response.statusText}`;
  }
}

async function fetchCommandCenterData(eventId: string): Promise<CommandCenterData> {
  try {
    const response = await fetch(`/api/events/${encodeURIComponent(eventId)}`, {
      cache: "no-store",
    });
    const body = await response.json().catch(() => null);

    if (!response.ok) {
      return {
        event: null,
        sessions: [],
        sps: [],
        assignments: [],
        availabilityRows: [],
        relatedEvents: [],
        errorMessage: body?.error || `Could not load event (${response.status}).`,
        sessionErrorMessage: "",
        availabilityErrorMessage: "",
        accessDenied: response.status === 403,
        notFound: response.status === 404,
      };
    }

    const loadedEvent = body?.event || null;
    const loadedSessions = Array.isArray(body?.sessions)
      ? sortEventSessionsForTimeline(body.sessions, getImportedYearHint(loadedEvent?.notes))
      : [];

    return {
      event: loadedEvent,
      redirectToPrimaryEventId: body?.redirectToPrimaryEventId || "",
      redirectToPrimaryEventName: body?.redirectToPrimaryEventName || "",
      sourceTrainingEventId: body?.sourceTrainingEventId || "",
      redirectToEventsSearch: body?.redirectToEventsSearch || "",
      sessions: loadedSessions,
      sps: Array.isArray(body?.sps) ? [...body.sps].sort(sortSPs) : [],
      assignments: Array.isArray(body?.assignments) ? body.assignments : [],
      availabilityRows: Array.isArray(body?.availabilityRows) ? body.availabilityRows : [],
      relatedEvents: Array.isArray(body?.relatedEvents) ? body.relatedEvents : [],
      viewerRole: body?.viewerRole || "unknown",
      spPortal: body?.spPortal || null,
      errorMessage: body?.errorMessage || "",
      sessionErrorMessage: body?.sessionErrorMessage || "",
      availabilityErrorMessage: body?.availabilityErrorMessage || "",
      accessDenied: false,
      notFound: false,
    };
  } catch (error) {
    return {
      event: null,
      sessions: [],
      sps: [],
      assignments: [],
      availabilityRows: [],
      relatedEvents: [],
      errorMessage: error instanceof Error ? error.message : "Could not load event.",
      sessionErrorMessage: "",
      availabilityErrorMessage: "",
      accessDenied: false,
      notFound: false,
    };
  }
}

function getRouteId(params: ReturnType<typeof useParams>) {
  const raw = params?.id;
  if (Array.isArray(raw)) return raw[0] || "";
  return typeof raw === "string" ? raw : "";
}

function normalizeEmail(value: string) {
  return asText(value).toLowerCase();
}

function normalizeLocationSignal(value: string) {
  return asText(value)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function detectLocationFitFromText(value: string): PollLocationFilter | "unknown" {
  const normalized = normalizeLocationSignal(value);
  if (!normalized) return "unknown";
  if (/\b(zoom|virtual|telehealth|online|remote|breakout)\b/.test(normalized)) return "virtual";
  if (/\b(elkins park|drexel elkins park|elkins|ep)\b/.test(normalized)) return "elkins_park";
  if (/\b(center city|centercity|cc)\b/.test(normalized)) return "center_city";
  return "unknown";
}

function normalizeMatchName(value: string) {
  return asText(value)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function parseWorkflowManualChecks(value?: string | null) {
  return Array.from(
    new Set(
      asText(value)
        .split("|")
        .map((item) => item.trim())
        .filter(Boolean)
    )
  );
}

function serializeWorkflowManualChecks(ids: string[]) {
  return Array.from(new Set(ids.map((item) => item.trim()).filter(Boolean))).join("|");
}

function hasPhysicalEventLocation(value: string | null | undefined) {
  const text = asText(value).toLowerCase();
  if (!text) return false;
  if (/\b(virtual|telehealth|breakout|online|remote)\b/.test(text)) return false;
  return /\b(campus|center|centre|building|room|suite|lab|hospital|clinic|hall|floor|site|onsite|on-site|in person|in-person|elkins park)\b/.test(text);
}

function inferEventModalityLabel(
  explicitEventTypeSet: Set<EditableEventType>,
  metadata: TrainingEventMetadata,
  event?: EventDetailRow | null
) {
  const explicit = asText(metadata.modality).toLowerCase();
  if (explicit === "virtual") return "Virtual";
  if (explicit === "hybrid") return "Hybrid";
  if (explicit === "in_person" || explicit === "in-person" || explicit === "in person") return "In-person";

  if (hasPhysicalEventLocation(event?.location)) return "In-person";
  if (explicitEventTypeSet.has("virtual")) return "Virtual";

  const source = [event?.name, event?.location, event?.status, event?.visibility].map(asText).join(" ").toLowerCase();
  if (/\b(virtual|vir|telehealth|breakout|online|remote)\b/.test(source)) return "Virtual";
  return "In-person";
}

function hasMaterialEvidence(metadata: TrainingEventMetadata) {
  return [
    metadata.case_file_url,
    metadata.case_files,
    metadata.doorsign_url,
    metadata.supplemental_doc_url,
    metadata.case_name,
  ].some((value) => Boolean(asText(value)));
}

function getDefaultRelatedEventKeyword(title?: string | null) {
  const text = asText(title);
  if (!text) return "";

  const courseTokenMatch = text.match(/\b[A-Z]{2,}\s*[-]?\s*(\d{3,4}[A-Z]?)\b/i);
  if (courseTokenMatch?.[1]) return courseTokenMatch[1];

  const numericMatch = text.match(/\b(\d{3,4}[A-Z]?)\b/);
  if (numericMatch?.[1]) return numericMatch[1];

  const tokens = text
    .split(/[^A-Za-z0-9]+/)
    .map((token) => token.trim())
    .filter((token) => token.length >= 3);

  return tokens[0] || "";
}

function normalizeRelatedEventFamilyTitle(title?: string | null) {
  return asText(title)
    .replace(/\b(SP\s*)?Training\b/gi, " ")
    .replace(/\b(Orientation|Prep|Onboarding)\b/gi, " ")
    .replace(/\s+/g, " ")
    .trim()
    .toLowerCase();
}

function getRelatedEventScheduleStatusLabel(args: {
  status?: string | null;
  trainingMetadata?: Partial<TrainingEventMetadata> | null;
}) {
  const scheduleStatus = asText(args.trainingMetadata?.schedule_status).toLowerCase();
  const rotationStatus = asText(args.trainingMetadata?.rotation_schedule_status).toLowerCase();
  const hasScheduleDraft = Boolean(
    asText(args.trainingMetadata?.schedule_builder_snapshot) ||
      asText(args.trainingMetadata?.schedule_last_saved_at) ||
      asText(args.trainingMetadata?.schedule_room_adjustments)
  );
  if (scheduleStatus === "complete" || rotationStatus === "complete") return "Schedule complete";
  const normalizedStatus = asText(args.status).toLowerCase();
  if (
    /needs?\s+(sp|staff|staffing)/.test(normalizedStatus) ||
    /staffing/.test(normalizedStatus) ||
    /needs?\s+coverage/.test(normalizedStatus)
  ) {
    return "Needs staffing";
  }
  if (scheduleStatus === "in_progress" || rotationStatus === "in_progress" || hasScheduleDraft) {
    return "Draft schedule";
  }
  return asText(args.status) || "Ready";
}

function parseRelatedEventsHiddenIds(value: string | null | undefined) {
  return Array.from(
    new Set(
      asText(value)
        .split(/[,;\n]/g)
        .map((entry) => asText(entry))
        .filter(Boolean)
    )
  );
}

function parseRelatedEventsConfirmedIds(value: string | null | undefined) {
  return new Set(
    asText(value)
      .split(/[,;\n]/g)
      .map((entry) => asText(entry))
      .filter(Boolean)
  );
}

function getSheetCellText(sheet: XLSX.WorkSheet, address: string) {
  return asText(sheet[address]?.v);
}

function parseTrainingImportWorkbook(file: File) {
  return file.arrayBuffer().then((buffer) => {
    const workbook = XLSX.read(buffer, { type: "array" });
    const firstSheetName = workbook.SheetNames[0];
    const sheet = firstSheetName ? workbook.Sheets[firstSheetName] : null;
    if (!sheet) {
      return {
        eventTitle: "",
        entries: [] as { email: string; name: string }[],
        facultyDetected: [] as string[],
        trainingDate: "",
        trainingTime: "",
        eventDatesDetected: [] as string[],
        eventTimesDetected: [] as string[],
      };
    }

    const eventTitle = getSheetCellText(sheet, "B1");
    const entries: { email: string; name: string }[] = [];
    const facultyDetected = new Set<string>();
    const trainingDate = getSheetCellText(sheet, "D14");
    const trainingTime = getSheetCellText(sheet, "D15");
    const eventDatesDetected: string[] = [];
    const eventTimesDetected: string[] = [];

    for (let row = 16; row <= 35; row += 1) {
      const email = getSheetCellText(sheet, `B${row}`);
      const name = getSheetCellText(sheet, `C${row}`);
      const faculty = getSheetCellText(sheet, `G${row}`);

      if (faculty) facultyDetected.add(faculty);
      if (!email && !name) continue;
      entries.push({ email, name });
    }

    ["E", "F", "G", "H", "I"].forEach((column) => {
      const dateValue = getSheetCellText(sheet, `${column}14`);
      const timeValue = getSheetCellText(sheet, `${column}15`);
      if (dateValue && timeValue) {
        eventDatesDetected.push(dateValue);
        eventTimesDetected.push(timeValue);
      }
    });

    return {
      eventTitle,
      entries,
      facultyDetected: Array.from(facultyDetected),
      trainingDate,
      trainingTime,
      eventDatesDetected,
      eventTimesDetected,
    };
  });
}


function getCapacityRequiredRoundCount(learnerCount: number | null | undefined, seatsPerRound: number | null | undefined) {
  const learners = typeof learnerCount === "number" && Number.isFinite(learnerCount) ? learnerCount : 0;
  const seats = typeof seatsPerRound === "number" && Number.isFinite(seatsPerRound) ? seatsPerRound : 0;
  if (learners <= 0 || seats <= 0) return 0;
  return Math.ceil(learners / seats);
}

function getOperationalRoundCountFromSources(options: {
  rosterLearnerCount?: number | null;
  activeLearnerCount?: number | null;
  roomCount?: number | null;
  savedRoundCount?: number | null;
  generatedRoundCount?: number | null;
  visibleRoundCount?: number | null;
  manualRoundOverride?: boolean | null;
}) {
  const capacityRoundCount = getCapacityRequiredRoundCount(
    options.rosterLearnerCount || options.activeLearnerCount || 0,
    options.roomCount || 0
  );

  const saved = typeof options.savedRoundCount === "number" && Number.isFinite(options.savedRoundCount) ? options.savedRoundCount : 0;
  const generated = typeof options.generatedRoundCount === "number" && Number.isFinite(options.generatedRoundCount) ? options.generatedRoundCount : 0;
  const visible = typeof options.visibleRoundCount === "number" && Number.isFinite(options.visibleRoundCount) ? options.visibleRoundCount : 0;

  // Manual override can intentionally shorten/limit rounds.
  // Otherwise capacity math must win over stale draft/generated values.
  if (options.manualRoundOverride && saved > 0) return saved;

  return Math.max(capacityRoundCount, saved, generated, visible, 0);
}

