  async function handleMarkMaterialsReviewed() {
    try {
      const nextNotes = upsertEventMetadata(
        upsertNoteValue(eventEditor.notes, "Materials Readiness", "materials_ready"),
        { training: { event_material_status: "materials_ready" } }
      );
      await persistTrainingNotes(nextNotes, "Materials marked reviewed.");
    } catch (error) {
      setEventSaveError(error instanceof Error ? error.message : "Could not mark materials reviewed.");
    }
  }

  async function persistTrainingNotes(nextNotes: string, successMessage: string) {
    if (!id) return false;

    setEventSaveMessage("Saving...");
    setEventSaveError("");

    const response = await fetch(`/api/events/${encodeURIComponent(id)}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        event_updates: {
          notes: nextNotes,
        },
      }),
    });

    if (!response.ok) {
      throw new Error(await parseApiError(response));
    }

    setEventEditor((current) => ({
      ...current,
      notes: nextNotes,
    }));
    setEvent((current) => (current ? { ...current, notes: nextNotes } : current));
    showSuccessMessage(successMessage);
    return true;
  }

  async function persistWorkflowChecks(nextChecks: Record<string, boolean>) {
    const selectedIds = Object.entries(nextChecks)
      .filter(([, complete]) => complete)
      .map(([workflowId]) => workflowId);
    const nextNotes = upsertEventMetadata(eventEditor.notes, {
      training: {
        workflow_manual_checks: serializeWorkflowManualChecks(selectedIds),
      },
    });
    const persisted = await persistTrainingNotes(nextNotes, "Workflow updated.");
    if (persisted) {
      setWorkflowChecks(nextChecks);
    }
    return persisted;
  }

  function buildNormalizedTrainingMetadataPartial(
    partial: Partial<TrainingEventMetadata>
  ): Partial<TrainingEventMetadata> {
    const next = { ...partial };

    if (next.preferred_training_date) {
      next.training_date = next.preferred_training_date;
    }
    if (next.preferred_training_time) {
      next.training_start_time = next.preferred_training_time;
    }
    if (next.preferred_training_end_time) {
      next.training_end_time = next.preferred_training_end_time;
    }
    if (next.zoom_url && !next.training_zoom_link) {
      next.training_zoom_link = next.zoom_url;
    }
    if (next.schedule_updated_at && !next.schedule_last_saved_at) {
      next.schedule_last_saved_at = next.schedule_updated_at;
    }
    if (next.hiring_email_sent_or_marked_at && !next.hiring_email_sent_at) {
      next.hiring_email_sent_at = next.hiring_email_sent_or_marked_at;
    }
    if (next.confirmation_email_sent_or_marked_at && !next.confirmation_email_sent_at) {
      next.confirmation_email_sent_at = next.confirmation_email_sent_or_marked_at;
    }
    if (next.staffing_doc_url && !next.event_material_status) {
      next.event_material_status = "materials_uploaded";
    }
    if (next.faculty_training_coordination_status === "draft_opened" && !next.faculty_training_coordination_requested) {
      next.faculty_training_coordination_requested = "yes";
    }
    if (
      next.faculty_training_coordination_status &&
      ["sent", "complete", "completed", "ready"].includes(next.faculty_training_coordination_status.toLowerCase()) &&
      !next.faculty_request_sent_at
    ) {
      next.faculty_request_sent_at =
        next.faculty_training_coordination_requested_at || new Date().toISOString();
    }
    if (next.faculty_training_coordination_requested_at && !next.faculty_training_coordination_requested) {
      next.faculty_training_coordination_requested = "yes";
    }
    if (next.faculty_request_sent_at) {
      if (!next.faculty_training_coordination_requested) {
        next.faculty_training_coordination_requested = "yes";
      }
      if (
        !next.faculty_training_coordination_status ||
        next.faculty_training_coordination_status === "requested"
      ) {
        next.faculty_training_coordination_status = "sent";
      }
      if (!next.faculty_training_coordination_requested_at) {
        next.faculty_training_coordination_requested_at = next.faculty_request_sent_at;
      }
    }

    return next;
  }

  async function persistTrainingMetadataFields(
    partial: Partial<TrainingEventMetadata>,
    successMessage: string
  ) {
    const nextNotes = upsertEventMetadata(eventEditor.notes, {
      training: buildNormalizedTrainingMetadataPartial(partial),
    });
    return persistTrainingNotes(nextNotes, successMessage);
  }

  async function handleSaveStudentInstructionsConfig() {
    const nextConfig = normalizeStudentInstructionsConfig({
      ...studentInstructionsDraft,
      updatedAt: new Date().toISOString(),
    });
    await persistTrainingMetadataFields(
      { student_instructions_config: serializeStudentInstructionsConfig(nextConfig) },
      "Student instructions saved."
    );
    setStudentInstructionsDraft(nextConfig);
    setStudentInstructionsSavedMessage("Saved");
  }

  function handleResetStudentInstructionsTemplate() {
    setStudentInstructionsDraft(defaultStudentInstructionsConfig);
    setStudentInstructionsSavedMessage("");
  }

  function updateStudentInstructionsDraft(partial: Partial<StudentInstructionsConfig>) {
    setStudentInstructionsDraft((current) => normalizeStudentInstructionsConfig({ ...current, ...partial }));
    setStudentInstructionsSavedMessage("");
  }

  async function persistScheduleRoomAdjustmentMetadata(
    nextAdjustments: ParsedScheduleRoomAdjustments,
    successMessage: string,
    options?: { nextRoomCount?: number }
  ) {
    const now = new Date().toISOString();
    const nextTrainingMetadata: Partial<TrainingEventMetadata> = {
      schedule_room_adjustments: serializeScheduleRoomAdjustments(nextAdjustments),
      schedule_last_saved_at: now,
      schedule_updated_at: now,
    };

    if (options?.nextRoomCount !== undefined) {
      nextTrainingMetadata.schedule_room_count = String(options.nextRoomCount);
    }

    const resolvedSchedulePreview = resolveScheduleBuilderPreviewSnapshot(trainingMetadata, {
      scheduleDay: scheduleBuilderDay,
    });
    const basePreviewSnapshot = scheduleBuilderPreviewDraft || resolvedSchedulePreview.serverSnapshot || null;

    if (basePreviewSnapshot) {
      const adjustedResolvedRounds = (basePreviewSnapshot.resolvedRounds || []).map((round, roundIndex) => {
        const roundNumber = Number(round.round) || roundIndex + 1;
        const roundAdjustments = nextAdjustments.get(roundNumber) || [];
        if (!roundAdjustments.length) return round;

        const adjustedRoomSlots = [...(round.roomSlots || [])];

        roundAdjustments.forEach((slotAdjustment) => {
          const slotIndex = Number(slotAdjustment.slotIndex);
          if (!Number.isFinite(slotIndex) || slotIndex < 0) return;

          const existingSlot = adjustedRoomSlots[slotIndex] || {
            roomName: getFallbackRoomLabel(slotIndex, roomNamingContext),
          };
          const hasExplicitManualRoomEdit = isExplicitManualRoomEdit(slotAdjustment);
          const hasLearnerOverride = Boolean(
            hasExplicitManualRoomEdit &&
            Object.prototype.hasOwnProperty.call(slotAdjustment, "learnerLabels")
          );
          const hasRoomNameOverride = Boolean(
            hasExplicitManualRoomEdit &&
            Object.prototype.hasOwnProperty.call(slotAdjustment, "roomName")
          );
          const hasSpNameOverride = Boolean(
            hasExplicitManualRoomEdit &&
            Object.prototype.hasOwnProperty.call(slotAdjustment, "spName")
          );
          const hasBackupSpOverride = Object.prototype.hasOwnProperty.call(slotAdjustment, "backupSpName");
          const hasCaseLabelOverride = Object.prototype.hasOwnProperty.call(slotAdjustment, "caseLabel");
          const hasRoleIdOverride = Object.prototype.hasOwnProperty.call(slotAdjustment, "roleId");
          const hasRoleLabelOverride = Object.prototype.hasOwnProperty.call(slotAdjustment, "roleLabel");
          const hasNotesOverride = Object.prototype.hasOwnProperty.call(slotAdjustment, "notes");

          adjustedRoomSlots[slotIndex] = {
            ...existingSlot,
            roomName: hasRoomNameOverride
              ? asText(slotAdjustment.roomName) || getFallbackRoomLabel(slotIndex, roomNamingContext)
              : asText(existingSlot.roomName) || getFallbackRoomLabel(slotIndex, roomNamingContext),
            assignedSpName: hasSpNameOverride ? asText(slotAdjustment.spName) : asText(existingSlot.assignedSpName),
            backupSpName: hasBackupSpOverride ? asText(slotAdjustment.backupSpName) : asText(existingSlot.backupSpName),
            learnerLabels: hasLearnerOverride
              ? normalizeLearnerNames(slotAdjustment.learnerLabels || [])
              : normalizeTextArray(existingSlot.learnerLabels),
            caseLabel: hasCaseLabelOverride ? asText(slotAdjustment.caseLabel) : asText(existingSlot.caseLabel),
            roleId: hasRoleIdOverride ? asText(slotAdjustment.roleId) : asText(existingSlot.roleId),
            roleLabel: hasRoleLabelOverride ? asText(slotAdjustment.roleLabel) : asText(existingSlot.roleLabel),
            notes: hasNotesOverride ? asText(slotAdjustment.notes) : asText(existingSlot.notes),
          };
        });

        return {
          ...round,
          roomSlots: adjustedRoomSlots,
        };
      });

      const nextPreviewSnapshot: ScheduleBuilderPreviewDraft = {
        ...basePreviewSnapshot,
        ...(options?.nextRoomCount !== undefined
          ? {
              examRoomCount: String(options.nextRoomCount),
              scheduleRoomCount: options.nextRoomCount,
            }
          : {}),
        resolvedRounds: adjustedResolvedRounds,
        scheduleRoundCount: adjustedResolvedRounds.length || basePreviewSnapshot.scheduleRoundCount,
        savedAt: now,
      };
      nextTrainingMetadata.schedule_builder_snapshot = encodeURIComponent(
        JSON.stringify(nextPreviewSnapshot)
      );
      const nextDays = new Map(resolvedSchedulePreview.serverDaySnapshots);
      nextDays.set(resolvedSchedulePreview.effectiveDay, nextPreviewSnapshot);
      nextTrainingMetadata.schedule_builder_days = JSON.stringify(
        Object.fromEntries(
          Array.from(nextDays.entries())
            .sort(([a], [b]) => a - b)
            .map(([day, snapshot]) => [String(day), encodeURIComponent(JSON.stringify(snapshot))])
        )
      );
      setScheduleBuilderPreviewDraft(nextPreviewSnapshot);
    }

    await persistTrainingMetadataFields(nextTrainingMetadata, successMessage);
  }

  async function handleRoundRoomAdjustment(
    slotIndex: number,
    partial: Partial<ScheduleRoomAdjustmentSlot>
  ) {
    const roundNumber = selectedResolvedRoundNumber;
    const nextAdjustments = upsertScheduleRoomAdjustmentSlot(
      activeScheduleRoomAdjustments,
      roundNumber,
      slotIndex,
      partial
    );
    setRoundOperationsDraftAdjustments(nextAdjustments);
    setRoundOperationsSaveState("unsaved");
    setRoundOperationsSaveError("");
  }

  async function handleMoveRoundAssignment(sourceRow: RoundRoomRow, targetRow: RoundRoomRow | undefined) {
    if (!targetRow || targetRow.slotIndex === sourceRow.slotIndex) return;
    const roundNumber = selectedResolvedRoundNumber;
    const sourcePrimarySpName = sourceRow.sp ? getFullName(sourceRow.sp) : asText((sourceRow as { primarySpName?: string }).primarySpName);
    const targetPrimarySpName = targetRow.sp ? getFullName(targetRow.sp) : asText((targetRow as { primarySpName?: string }).primarySpName);
    let nextAdjustments = upsertScheduleRoomAdjustmentSlot(
      activeScheduleRoomAdjustments,
      roundNumber,
      targetRow.slotIndex,
      {
        manualOverride: true,
        source: "manual-room-edit",
        learnerLabels: sourceRow.learnerLabels,
        spName: sourcePrimarySpName,
        backupSpName: sourceRow.backupSpName,
        caseLabel: sourceRow.caseLabel,
        roleId: sourceRow.roleId,
        roleLabel: sourceRow.roleLabel,
        notes: sourceRow.notes,
      }
    );
    nextAdjustments = upsertScheduleRoomAdjustmentSlot(
      nextAdjustments,
      roundNumber,
      sourceRow.slotIndex,
      {
        manualOverride: true,
        source: "manual-room-edit",
        learnerLabels: targetRow.learnerLabels,
        spName: targetPrimarySpName,
        backupSpName: targetRow.backupSpName,
        caseLabel: targetRow.caseLabel,
        roleId: targetRow.roleId,
        roleLabel: targetRow.roleLabel,
        notes: targetRow.notes,
      }
    );
    setRoundOperationsDraftAdjustments(nextAdjustments);
    setRoundOperationsSaveState("unsaved");
    setRoundOperationsSaveError("");
  }

  async function handleSaveRoundOperationsChanges() {
    const payload = roundOperationsDraftAdjustments || activeScheduleRoomAdjustments;
    setRoundOperationsSaveState("saving");
    setRoundOperationsSaveError("");
    try {
      await persistScheduleRoomAdjustmentMetadata(payload, "Round changes saved.");
      const now = new Date().toISOString();
      setRoundOperationsDraftAdjustments(null);
      setRoundOperationsLastSavedAt(now);
      setRoundOperationsSaveState("saved");
    } catch (error) {
      setRoundOperationsSaveState("error");
      setRoundOperationsSaveError(error instanceof Error ? error.message : "Could not save round changes.");
    }
  }

  async function handleRoundRoomCountChange(delta: 1 | -1) {
    const nextRoomCount = Math.max(1, effectiveRoomCount + delta);
    if (delta < 0) {
      const lastRoom = selectedRoundScheduleRows[selectedRoundScheduleRows.length - 1];
      if (
        lastRoom &&
        (lastRoom.assignment || lastRoom.learnerLabels.length || asText(lastRoom.caseLabel)) &&
        !window.confirm(`Remove ${lastRoom.roomName || "the last room"} from this schedule view? It has assignments or learner data.`)
      ) {
        return;
      }
    }

    await persistScheduleRoomAdjustmentMetadata(
      activeScheduleRoomAdjustments,
      delta > 0 ? "Room added." : "Room removed.",
      { nextRoomCount }
    );
  }

  function queueCommandContentScroll() {
    if (typeof window === "undefined") return;
    window.requestAnimationFrame(() => {
      activeCommandContentRef.current?.scrollIntoView({ behavior: "smooth", block: "start" });
      activeCommandContentRef.current?.focus?.({ preventScroll: true });
    });
  }

  function handleRelatedEventDateSwitch(nextEventId: string) {
    if (!nextEventId || nextEventId === id) return;
    if (saving || roundOperationsSaveState === "saving") return;
    if (
      roundOperationsSaveState === "unsaved" &&
      !window.confirm("You have unsaved round assignment changes. Switch event dates and discard those unsaved changes?")
    ) {
      return;
    }
    setLoading(true);
    const nextUrl = eventFamilyQueryKey
      ? `/events/${encodeURIComponent(nextEventId)}?family=${encodeURIComponent(eventFamilyQueryKey)}`
      : `/events/${encodeURIComponent(nextEventId)}`;
    router.push(nextUrl);
  }

  function buildEventSchedulePreviewHref(
    kind: EventSchedulePreviewKind,
    previewFamily?: "ticket" | "schedule",
    options?: { download?: boolean; downloadMode?: "schedule" | "studentInstructions" }
  ) {
    const params = new URLSearchParams();
    params.set("source", "event-preview");
    params.set("view", roundCompanionView);
    params.set("preview", kind);
    params.set("previewMode", "1");
    if (scheduleBuilderDay) {
      params.set("day", String(scheduleBuilderDay));
    }
    if (previewFamily) {
      params.set("previewFamily", previewFamily);
    }
    if (options?.downloadMode === "studentInstructions") {
      params.set("downloadMode", "studentInstructions");
      params.set("preview", "student");
      params.set("view", "student");
      params.set("previewFamily", "schedule");
    } else if (options?.download) {
      params.set("downloadMode", "1");
    }

    if (selectedRotationRound) {
      params.set("round", selectedRotationRound.key);
      params.set("roundIndex", String(activeSelectedRotationRoundIndex + 1));
    }

    return `/events/${encodeURIComponent(id)}/schedule-builder?${params.toString()}`;
  }

  function handleOpenEventScheduleRouteInNewTab(kind: EventSchedulePreviewKind, previewFamily?: "ticket" | "schedule") {
    const href = buildEventSchedulePreviewHref(kind, previewFamily);
    window.open(href, "_blank", "noopener,noreferrer");
  }

  function handleGenerateStudentInstructionsPdf() {
    const href = buildEventSchedulePreviewHref("student", "schedule", { downloadMode: "studentInstructions" });
    window.open(href, "_blank", "noopener,noreferrer");
  }

