  function openMaterialPreview(args: {
    title: string;
    rawUrl: string;
    storagePath?: string | null;
    fileName?: string | null;
  }) {
    const safeUrl = asText(args.rawUrl);
    const storagePath = asText(args.storagePath);
    const fileName = asText(args.fileName) || getFilenameFromUrl(safeUrl) || getFilenameFromUrl(storagePath) || "training-material";
    if (!safeUrl && !storagePath) {
      console.warn("[materials] preview source missing", { hasTitle: Boolean(args.title) });
      setMaterialPreviewLoading(false);
      setMaterialPreviewError("File missing or access expired. Please download the file or upload it again.");
      setMaterialOpenInNewTabError("");
      setMaterialPreviewText("");
      setMaterialPreviewHtml("");
      setMaterialPreview({
        title: args.title,
        previewUrl: "about:blank",
        downloadUrl: "",
        openInNewTabUrl: "",
        fileName,
        kind: "unsupported",
      });
      return;
    }
    const assetUrls = buildTrainingMaterialAssetUrls({
      eventId: id,
      rawUrl: safeUrl,
      storagePath,
      fileName,
    });
    const previewKind = getMaterialPreviewKind(assetUrls.fileName, safeUrl, storagePath, assetUrls.previewUrl);
    const isUnsupportedPreview = previewKind === "unsupported";
    setMaterialPreviewLoading(previewKind !== "unsupported");
    setMaterialPreviewError("");
    setMaterialOpenInNewTabError("");
    setMaterialPreviewText("");
    setMaterialPreviewHtml("");
    setMaterialPreview({
      title: args.title,
      previewUrl: assetUrls.previewUrl,
      downloadUrl: assetUrls.downloadUrl,
      openInNewTabUrl: isUnsupportedPreview ? assetUrls.downloadUrl : assetUrls.openInNewTabUrl,
      fileName: assetUrls.fileName,
      kind: previewKind,
    });
  }

  function closeMaterialPreview() {
    setMaterialPreview(null);
    setMaterialPreviewLoading(false);
    setMaterialPreviewError("");
    setMaterialOpenInNewTabError("");
    setMaterialPreviewText("");
    setMaterialPreviewHtml("");
  }

  function handleOpenMaterialInNewTab() {
    if (!materialPreview) return;

    const rawUrl = asText(materialPreview.openInNewTabUrl || materialPreview.previewUrl);
    if (!rawUrl || rawUrl.toLowerCase() === "about:blank") {
      setMaterialOpenInNewTabError("Could not prepare a new-tab view for this material.");
      return;
    }

    let targetUrl = rawUrl;
    try {
      const resolvedUrl = new URL(rawUrl, window.location.origin);
      if (!["http:", "https:", "blob:"].includes(resolvedUrl.protocol)) {
        throw new Error("Unsupported material preview URL.");
      }
      targetUrl =
        ["http:", "https:"].includes(resolvedUrl.protocol) &&
        resolvedUrl.origin === window.location.origin
          ? `${resolvedUrl.pathname}${resolvedUrl.search}${resolvedUrl.hash}`
          : resolvedUrl.href;
    } catch {
      setMaterialOpenInNewTabError("Could not prepare a new-tab view for this material.");
      return;
    }

    setMaterialOpenInNewTabError("");
    window.open(targetUrl, "_blank", "noopener,noreferrer");
  }

  function setTrainingMaterialSavingState(kind: TrainingMaterialKind, savingState: boolean) {
    setTrainingMaterialSaving((current) => ({
      ...current,
      [kind]: savingState,
    }));
  }

  function openTrainingMaterialPicker(kind: TrainingMaterialKind) {
    if (kind === "case_file") {
      openCaseFilePicker({ mode: caseFileEntries.length ? "replace" : "add", index: 0 });
      return;
    }

    const inputRef =
      kind === "doorsign"
        ? doorsignInputRef
        : kind === "staffing_doc"
        ? staffingDocInputRef
        : supplementalDocInputRef;

    inputRef.current?.click();
  }

  function openCaseFilePicker(target: CaseFileUploadTarget = { mode: "add" }) {
    setCaseFileUploadTarget(target);
    window.setTimeout(() => caseFileInputRef.current?.click(), 0);
  }

  async function handleTrainingMaterialUpload(
    kind: TrainingMaterialKind,
    file: File | null,
    caseTargetOverride?: CaseFileUploadTarget
  ) {
    if (!file || !id) return;

    const fieldConfig = trainingMaterialFieldMap[kind];
    const resolvedCaseFileUploadTarget = caseTargetOverride || caseFileUploadTarget;
    const replaceCaseEntry =
      kind === "case_file" && resolvedCaseFileUploadTarget.mode === "replace"
        ? caseFileEntries[Math.max(Number(resolvedCaseFileUploadTarget.index || 0), 0)] || primaryCaseFileEntry
        : null;
    const replacePath =
      kind === "case_file"
        ? asText(replaceCaseEntry?.storagePath)
        : asText(trainingMetadata[fieldConfig.storagePathKey]);
    const formData = new FormData();
    formData.append("eventId", id);
    formData.append("kind", kind);
    formData.append("file", file);
    if (replacePath) {
      formData.append("replacePath", replacePath);
    }

    setTrainingMaterialSavingState(kind, true);
    setEventSaveMessage("");
    setEventSaveError("");

    try {
      const response = await fetch("/api/uploads/training-material", {
        method: "POST",
        body: formData,
      });

      const body = (await response.json().catch(() => null)) as
        | {
            error?: string;
            material?: {
              filename?: string;
              uploaded_at?: string;
              uploaded_by?: string;
              storage_path?: string;
              url?: string;
            };
          }
        | null;

      if (!response.ok || !body?.material) {
        throw new Error(body?.error || `Could not upload ${fieldConfig.label.toLowerCase()}.`);
      }

      const uploadedCaseEntry = normalizeCaseFileEntry(
        {
          ...(replaceCaseEntry || {}),
          id: body.material.storage_path || body.material.url || `${Date.now()}-${body.material.filename}`,
          name: asText(body.material.filename),
          url: asText(body.material.url),
          storagePath: asText(body.material.storage_path),
          uploadedAt: asText(body.material.uploaded_at),
          uploadedBy: asText(body.material.uploaded_by),
        },
        caseFileEntries.length
      );
      const nextCaseEntries =
        kind === "case_file" && uploadedCaseEntry
          ? (() => {
              const existingEntries = caseFileEntries.length
                ? [...caseFileEntries]
                : legacyCaseFileEntry
                  ? [legacyCaseFileEntry]
                  : [];
              if (resolvedCaseFileUploadTarget.mode === "replace") {
                const replaceIndex = Math.max(Number(resolvedCaseFileUploadTarget.index || 0), 0);
                if (existingEntries[replaceIndex]) {
                  existingEntries[replaceIndex] = uploadedCaseEntry;
                  return existingEntries;
                }
              }
              return [...existingEntries, uploadedCaseEntry];
            })()
          : [];
      const primaryCaseEntry = kind === "case_file" ? nextCaseEntries[0] || uploadedCaseEntry : null;
      const nextNotes = upsertEventMetadata(eventEditor.notes, { training: {
        [fieldConfig.urlKey]: kind === "case_file" ? asText(primaryCaseEntry?.url) : asText(body.material.url),
        [fieldConfig.nameKey]: kind === "case_file" ? asText(primaryCaseEntry?.name) : asText(body.material.filename),
        [fieldConfig.storagePathKey]: kind === "case_file" ? asText(primaryCaseEntry?.storagePath) : asText(body.material.storage_path),
        [fieldConfig.uploadedAtKey]: kind === "case_file" ? asText(primaryCaseEntry?.uploadedAt) : asText(body.material.uploaded_at),
        [fieldConfig.uploadedByKey]: kind === "case_file" ? asText(primaryCaseEntry?.uploadedBy) : asText(body.material.uploaded_by),
        ...(kind === "case_file"
          ? {
              case_files: serializeCaseFileEntries(nextCaseEntries),
              case_manager_cases: serializeCaseFileEntries(nextCaseEntries),
            }
          : {}),
        ...(kind === "staffing_doc"
          ? {
              event_material_status: "materials_uploaded",
            }
          : {}),
      }});

      await persistTrainingNotes(
        nextNotes,
        kind === "staffing_doc" ? "Event material uploaded." : `${fieldConfig.label} saved to training materials.`
      );
    } catch (error) {
      setEventSaveError(
        error instanceof Error
          ? error.message
          : `Could not upload ${fieldConfig.label.toLowerCase()}.`
      );
    } finally {
      setTrainingMaterialSavingState(kind, false);
    }
  }

  useEffect(() => {
    if (!materialPreview) return;
    const preview = materialPreview;

    if (preview.kind === "unsupported") {
      setMaterialPreviewLoading(false);
      setMaterialPreviewError("");
      setMaterialPreviewText("");
      setMaterialPreviewHtml("");
      return;
    }

    if (preview.kind !== "text" && preview.kind !== "html") {
      setMaterialPreviewText("");
      setMaterialPreviewHtml("");
      return;
    }

    let cancelled = false;
    setMaterialPreviewLoading(true);
    setMaterialPreviewError("");
    setMaterialPreviewText("");
    setMaterialPreviewHtml("");

    async function loadDocumentPreview() {
      try {
        const response = await fetch(preview.previewUrl, { cache: "no-store" });
        if (!response.ok) {
          throw new Error(getMaterialPreviewLoadError(response));
        }
        const text = await response.text();
        if (cancelled) return;
        if (preview.kind === "html") {
          setMaterialPreviewHtml(text);
        } else {
          setMaterialPreviewText(text);
        }
        setMaterialPreviewLoading(false);
      } catch (error) {
        if (cancelled) return;
        console.warn("[materials] preview load failed", {
          kind: preview.kind,
          error: error instanceof Error ? error.message : "error",
        });
        setMaterialPreviewError(
          preview.kind === "html"
            ? error instanceof Error
              ? error.message
              : "Could not load preview. Please download the file."
            : error instanceof Error
              ? error.message
              : "Could not load preview. Please download the file."
        );
        setMaterialPreviewLoading(false);
      }
    }

    void loadDocumentPreview();
    return () => {
      cancelled = true;
    };
  }, [id, materialPreview]);

  useEffect(() => {
    if (!materialPreviewLoading || !materialPreview) return;
    if (!["pdf", "iframe", "image"].includes(materialPreview.kind)) return;

    let cancelled = false;
    const controller = new AbortController();
    const preview = materialPreview;

    async function validateInlinePreviewUrl() {
      if (!isSameOriginPreviewUrl(preview.previewUrl)) return;

      try {
        const response = await fetch(preview.previewUrl, {
          cache: "no-store",
          signal: controller.signal,
        });
        if (response.body) void response.body.cancel().catch(() => undefined);
        if (!response.ok && !cancelled) {
          setMaterialPreviewError(getMaterialPreviewLoadError(response));
          setMaterialPreviewLoading(false);
        }
      } catch (error) {
        if (cancelled || (error instanceof DOMException && error.name === "AbortError")) return;
        console.warn("[materials] inline preview preflight failed", {
          kind: preview.kind,
          error: error instanceof Error ? error.message : "error",
        });
        setMaterialPreviewError("Could not load preview. Please download the file.");
        setMaterialPreviewLoading(false);
      }
    }

    void validateInlinePreviewUrl();

    const timeout = window.setTimeout(() => {
      console.warn("[materials] preview timed out", { kind: preview.kind });
      setMaterialPreviewLoading(false);
      setMaterialPreviewError("Could not load preview. Please download the file.");
    }, 8000);

    return () => {
      cancelled = true;
      controller.abort();
      window.clearTimeout(timeout);
    };
  }, [id, materialPreview, materialPreviewLoading]);

  async function handleRemoveTrainingMaterial(kind: TrainingMaterialKind) {
    if (!id) return;
    if (kind === "case_file") {
      await handleRemoveCaseFile(0);
      return;
    }

    const fieldConfig = trainingMaterialFieldMap[kind];
    const storagePath = asText(trainingMetadata[fieldConfig.storagePathKey]);

    setTrainingMaterialSavingState(kind, true);
    setEventSaveMessage("");
    setEventSaveError("");

    try {
      if (storagePath) {
        const response = await fetch("/api/uploads/training-material", {
          method: "DELETE",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            eventId: id,
            path: storagePath,
          }),
        });

        if (!response.ok) {
          throw new Error(await parseApiError(response));
        }
      }

      const nextNotes = upsertEventMetadata(eventEditor.notes, { training: {
        [fieldConfig.urlKey]: "",
        [fieldConfig.nameKey]: "",
        [fieldConfig.storagePathKey]: "",
        [fieldConfig.uploadedAtKey]: "",
        [fieldConfig.uploadedByKey]: "",
        ...(kind === "staffing_doc"
          ? {
              event_material_status: "",
            }
          : {}),
      }});

      await persistTrainingNotes(
        nextNotes,
        kind === "staffing_doc" ? "Staffing doc removed." : `${fieldConfig.label} removed.`
      );
    } catch (error) {
      setEventSaveError(
        error instanceof Error
          ? error.message
          : `Could not remove ${fieldConfig.label.toLowerCase()}.`
      );
    } finally {
      setTrainingMaterialSavingState(kind, false);
    }
  }

  async function handleRemoveCaseFile(index: number) {
    if (!id) return;
    const caseEntry = caseFileEntries[index];
    if (!caseEntry) return;
    if (!window.confirm(`Remove ${caseEntry.name || "this case file"} from this event?`)) return;

    setTrainingMaterialSavingState("case_file", true);
    setEventSaveMessage("");
    setEventSaveError("");

    try {
      if (caseEntry.storagePath) {
        const response = await fetch("/api/uploads/training-material", {
          method: "DELETE",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            eventId: id,
            path: caseEntry.storagePath,
          }),
        });

        if (!response.ok) {
          throw new Error(await parseApiError(response));
        }
      }

      const nextCaseEntries = caseFileEntries.filter((_, entryIndex) => entryIndex !== index);
      const primaryCaseEntry = nextCaseEntries[0] || null;
      const nextNotes = upsertEventMetadata(eventEditor.notes, { training: {
        case_name: asText(primaryCaseEntry?.name),
        case_count: nextCaseEntries.length ? String(nextCaseEntries.length) : "",
        case_file_url: asText(primaryCaseEntry?.url),
        case_file_name: asText(primaryCaseEntry?.name),
        case_file_storage_path: asText(primaryCaseEntry?.storagePath),
        case_file_uploaded_at: asText(primaryCaseEntry?.uploadedAt),
        case_file_uploaded_by: asText(primaryCaseEntry?.uploadedBy),
        case_files: nextCaseEntries.length ? serializeCaseFileEntries(nextCaseEntries) : "",
        case_manager_cases: nextCaseEntries.length ? serializeCaseFileEntries(nextCaseEntries) : "",
      }});

      await persistTrainingNotes(nextNotes, "Case file removed.");
    } catch (error) {
      setEventSaveError(error instanceof Error ? error.message : "Could not remove case file.");
    } finally {
      setTrainingMaterialSavingState("case_file", false);
    }
  }

  async function handleSaveCaseManagerEntry(index: number, partial: Partial<CaseFileEntry>, message = "Case updated.") {
    if (!id) return;
    const nextCaseEntries = patchCaseFileEntry(caseFileEntries, index, partial);
    const primaryCaseEntry = nextCaseEntries[0] || null;
    setTrainingMaterialSavingState("case_file", true);
    setEventSaveMessage("");
    setEventSaveError("");

    try {
      const nextNotes = upsertEventMetadata(eventEditor.notes, { training: {
        case_name: asText(primaryCaseEntry?.name),
        case_file_url: asText(primaryCaseEntry?.url),
        case_file_name: asText(primaryCaseEntry?.name),
        case_file_storage_path: asText(primaryCaseEntry?.storagePath),
        case_file_uploaded_at: asText(primaryCaseEntry?.uploadedAt),
        case_file_uploaded_by: asText(primaryCaseEntry?.uploadedBy),
        case_files: serializeCaseFileEntries(nextCaseEntries),
        case_manager_cases: serializeCaseFileEntries(nextCaseEntries),
        event_material_status: nextCaseEntries.length ? "materials_uploaded" : trainingMetadata.event_material_status,
      }});
      await persistTrainingNotes(nextNotes, message);
    } catch (error) {
      setEventSaveError(error instanceof Error ? error.message : "Could not save case details.");
    } finally {
      setTrainingMaterialSavingState("case_file", false);
    }
  }

  async function handleSaveCaseRoles(index: number, partial: { hasRoles?: boolean; roles?: CaseRoleEntry[] }, message = "Case roles saved.") {
    const caseEntry = caseFileEntries[index];
    if (!caseEntry) return;
    const roles = partial.roles !== undefined ? normalizeCaseRoleEntries(partial.roles, caseEntry.id) : caseEntry.roles || [];
    await handleSaveCaseManagerEntry(
      index,
      {
        hasRoles: partial.hasRoles !== undefined ? partial.hasRoles : Boolean(roles.length || caseEntry.hasRoles),
        roles,
      },
      message
    );
  }

  async function handleEnsureCaseCount(nextCountValue: string) {
    const nextCount = Math.max(0, Math.min(20, Number.parseInt(nextCountValue, 10) || 0));
    const nextCaseEntries = [...caseFileEntries];
    while (nextCaseEntries.length < nextCount) {
      const caseIndex = nextCaseEntries.length;
      nextCaseEntries.push({
        id: `manual-case-${Date.now()}-${caseIndex}`,
        name: `Case ${caseIndex + 1}`,
        url: "",
        storagePath: "",
        uploadedAt: "",
        uploadedBy: "",
        encounterMinutes: trainingMetadata.case_roles_per_case ? "" : "",
        checklistMinutes: "",
        feedbackMinutes: "",
        notes: "",
        roomAssignment: `Exam ${caseIndex + 1}`,
        status: "active",
      });
    }
    const trimmedEntries = nextCaseEntries.slice(0, nextCount);
    const primaryCaseEntry = trimmedEntries[0] || null;
    try {
      const nextNotes = upsertEventMetadata(eventEditor.notes, { training: {
        case_count: String(nextCount),
        case_name: asText(primaryCaseEntry?.name),
        case_file_url: asText(primaryCaseEntry?.url),
        case_file_name: asText(primaryCaseEntry?.name),
        case_file_storage_path: asText(primaryCaseEntry?.storagePath),
        case_files: serializeCaseFileEntries(trimmedEntries),
        case_manager_cases: serializeCaseFileEntries(trimmedEntries),
      }});
      await persistTrainingNotes(nextNotes, "Case count saved.");
    } catch (error) {
      setEventSaveError(error instanceof Error ? error.message : "Could not save case count.");
    }
  }

  async function handleTrainingWorkbookImport(file: File | null) {
    if (!file || !id) return;

    setTrainingImportError("");
    setTrainingImportResult(null);
    setTrainingImporting(true);
    setEventSaveMessage("");
    setEventSaveError("");

    try {
      const parsed = await parseTrainingImportWorkbook(file);
      const matchedAssigned: string[] = [];
      const alreadyAssigned: string[] = [];
      const notFound: string[] = [];
      const matchedSpIds: string[] = [];

      parsed.entries.forEach((entry) => {
        const byEmail = entry.email ? spByEmail.get(normalizeEmail(entry.email)) : undefined;
        const byName = entry.name ? spByNormalizedName.get(normalizeMatchName(entry.name)) : undefined;
        const match = byEmail || byName;

        if (!match) {
          notFound.push(entry.email || entry.name || "Unknown entry");
          return;
        }

        const label = `${getFullName(match)}${getEmail(match) ? ` (${getEmail(match)})` : ""}`;
        if (assignedSpIds.has(String(match.id)) || matchedSpIds.includes(String(match.id))) {
          alreadyAssigned.push(label);
          return;
        }

        matchedSpIds.push(String(match.id));
        matchedAssigned.push(label);
      });

      if (matchedSpIds.length) {
        await assignMultipleSpIds(
          matchedSpIds,
          `${matchedSpIds.length} SP${matchedSpIds.length === 1 ? "" : "s"} imported and confirmed.`,
          { status: "confirmed", confirmed: true }
        );
      }

      const importMetadataUpdate: Partial<TrainingEventMetadata> = {
        imported_event_info_at: new Date().toISOString(),
        imported_event_info_count: String(parsed.entries.length),
        imported_training_date: parsed.trainingDate,
        imported_training_time: parsed.trainingTime,
        imported_event_times: parsed.eventTimesDetected.join(" | "),
        imported_event_dates_count: String(parsed.eventDatesDetected.length),
      };

      if (parsed.facultyDetected.length && !trainingMetadata.faculty_names.trim()) {
        importMetadataUpdate.faculty_names = parsed.facultyDetected.join(", ");
      }

      await persistTrainingMetadataFields(importMetadataUpdate, "Event info imported.");

      setTrainingImportResult({
        eventTitle: parsed.eventTitle,
        matchedAssigned,
        alreadyAssigned,
        notFound,
        facultyDetected: parsed.facultyDetected,
        importedAt: new Date().toISOString(),
        importedCount: parsed.entries.length,
        confirmedCount: matchedAssigned.length,
        trainingDate: parsed.trainingDate,
        trainingTime: parsed.trainingTime,
        eventDatesDetected: parsed.eventDatesDetected,
        eventTimesDetected: parsed.eventTimesDetected,
      });
    } catch (error) {
      setTrainingImportError(
        error instanceof Error ? error.message : "Could not import SP Event Info workbook."
      );
    } finally {
      setTrainingImporting(false);
    }
  }

  async function handlePreviewRelatedEvents() {
    if (!id || !relatedKeyword.trim()) {
      setRelatedPushError("Enter a keyword to preview related events.");
      setRelatedMatches([]);
      return;
    }

    setRelatedPreviewLoading(true);
    setRelatedPushError("");
    setRelatedPushSummary(null);

    try {
      const response = await fetch(`/api/events/${encodeURIComponent(id)}/push-related`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          mode: "preview",
          keyword: relatedKeyword.trim(),
          mustInclude: relatedMustInclude.trim(),
          exclude: relatedExclude.trim(),
          excludeCurrent: relatedExcludeCurrent,
        }),
      });

      const body = (await response.json().catch(() => null)) as
        | {
            error?: string;
            events?: RelatedEventPreview[];
          }
        | null;

      if (!response.ok) {
        throw new Error(body?.error || "Could not preview related events.");
      }

      const matches = Array.isArray(body?.events) ? body.events : [];
      setRelatedMatches(matches);
      setSelectedRelatedTargetIds(
        matches.filter((event) => event.exact_course_match).map((event) => event.id)
      );
    } catch (error) {
      setRelatedPushError(
        error instanceof Error ? error.message : "Could not preview related events."
      );
      setRelatedMatches([]);
    } finally {
      setRelatedPreviewLoading(false);
    }
  }

  function handleToggleRelatedCopyOption(option: RelatedCopyOption) {
    setRelatedPushSummary(null);
    setRelatedPushError("");
    setRelatedCopyOptions((current) =>
      current.includes(option)
        ? current.filter((item) => item !== option)
        : [...current, option]
    );
  }

  function handleToggleRelatedTarget(eventId: string) {
    setRelatedPushSummary(null);
    setRelatedPushError("");
    setSelectedRelatedTargetIds((current) =>
      current.includes(eventId)
        ? current.filter((id) => id !== eventId)
        : [...current, eventId]
    );
  }

  async function handlePushToRelatedEvents() {
    if (!id || !relatedKeyword.trim()) {
      setRelatedPushError("Enter a keyword before pushing to related events.");
      return;
    }

    if (!relatedMatches.length) {
      setRelatedPushError("Preview matching events before pushing selected info.");
      return;
    }

    if (!selectedRelatedTargetIds.length) {
      setRelatedPushError("Check at least one target event before pushing.");
      return;
    }

    if (!relatedCopyOptions.length) {
      setRelatedPushError("Select at least one thing to copy.");
      return;
    }

    setRelatedPushSaving(true);
    setRelatedPushError("");
    setRelatedPushSummary(null);

    try {
      const response = await fetch(`/api/events/${encodeURIComponent(id)}/push-related`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          mode: "push",
          keyword: relatedKeyword.trim(),
          mustInclude: relatedMustInclude.trim(),
          exclude: relatedExclude.trim(),
          excludeCurrent: relatedExcludeCurrent,
          targetEventIds: selectedRelatedTargetIds,
          copyOptions: relatedCopyOptions,
        }),
      });

      const body = (await response.json().catch(() => null)) as
        | {
            error?: string;
            summary?: PushRelatedSummary;
          }
        | null;

      if (!response.ok || !body?.summary) {
        throw new Error(body?.error || "Could not push selected info to related events.");
      }

      setRelatedPushSummary(body.summary);
      showSuccessMessage("Pushed successfully");
      await handlePreviewRelatedEvents();
    } catch (error) {
      setRelatedPushError(
        error instanceof Error
          ? error.message
          : "Could not push selected info to related events."
      );
    } finally {
      setRelatedPushSaving(false);
    }
  }

  useEffect(() => {
    let cancelled = false;

    if (!id) {
      return;
    }

    setLoading(true);

    const refresh = () => {
      void fetchCommandCenterData(id).then((result) => {
        if (cancelled) return;

        setEvent(result.event);
        setEventEditor({
          name: result.event?.name || "",
          status: result.event?.status || "",
          visibility: result.event?.visibility || "",
          location: result.event?.location || "",
          notes: result.event?.notes || "",
          sp_needed:
            result.event?.sp_needed === null || result.event?.sp_needed === undefined
              ? ""
              : String(result.event.sp_needed),
        });
        setSessionEditor(
          getEventDetailsSessionEditorState(
            result.sessions,
            result.event?.date_text,
            parseEventMetadata(result.event?.notes).training
          )
        );
        setSessions(result.sessions);
        setSps(result.sps);
        setAssignments(result.assignments);
        setAvailabilityRows(result.availabilityRows);
        setRelatedOperationalEvents(result.relatedEvents);
        setViewerRole(result.viewerRole || "unknown");
        setSpPortal(result.spPortal || null);
        setErrorMessage(result.errorMessage);
        setSessionErrorMessage(result.sessionErrorMessage);
        setAvailabilityErrorMessage(result.availabilityErrorMessage);
        setAccessDenied(result.accessDenied);
        setNotFound(result.notFound);
        setLoading(false);
      });
    };

    refresh();

    window.addEventListener("focus", refresh);

    return () => {
      cancelled = true;
      window.removeEventListener("focus", refresh);
    };
  }, [id]);

  useEffect(() => {
    let cancelled = false;

    async function loadCurrentUser() {
      try {
        const response = await fetch("/api/me", {
          cache: "no-store",
          credentials: "include",
        });
        if (!response.ok) return;

        const body = (await response.json().catch(() => null)) as
          | {
              user?: { email?: string | null };
              profile?: {
                full_name?: string | null;
                schedule_name?: string | null;
                email?: string | null;
              } | null;
            }
          | null;

        if (cancelled || !body) return;
        setMe({
          email: asText(body.profile?.email) || asText(body.user?.email),
          fullName: asText(body.profile?.full_name),
          scheduleName: asText(body.profile?.schedule_name),
        });
      } catch {
        return;
      }
    }

    void loadCurrentUser();

    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    if (!defaultRelatedKeyword) return;
    setRelatedKeyword((current) => (current ? current : defaultRelatedKeyword));
  }, [defaultRelatedKeyword]);

  useEffect(() => {
    const next: Record<string, boolean> = {};
    persistedWorkflowChecks.forEach((id) => {
      next[id] = true;
    });
    setWorkflowChecks(next);
  }, [persistedWorkflowChecks]);

  useEffect(() => {
    return () => {
      clearActionFeedbackTimers();
    };
  }, []);

  useEffect(() => {
    setCountdownNowMs(Date.now());
    const interval = window.setInterval(() => {
      setCountdownNowMs(Date.now());
    }, 1000);
    return () => window.clearInterval(interval);
  }, []);

  useEffect(() => {
    if (!canRunLiveEventMode || commandCenterMode !== "live") return;
    const interval = window.setInterval(() => {
      setLiveNowMs(Date.now());
    }, 1000);
    return () => window.clearInterval(interval);
  }, [canRunLiveEventMode, commandCenterMode]);

  function handlePauseLiveSchedule() {
    if (livePausedAtMs !== null) return;
    setLivePausedAtMs(Date.now());
    showSuccessMessage("Live schedule paused.");
  }

  function handleResumeLiveSchedule() {
    if (livePausedAtMs === null) return;
    const pauseDurationMinutes = Math.max(0, Math.round((Date.now() - livePausedAtMs) / 60000));
    setLiveDelayMinutes((current) => current + pauseDurationMinutes);
    setLivePausedAtMs(null);
    showSuccessMessage(
      pauseDurationMinutes > 0
        ? `Event resumed with ${pauseDurationMinutes} minute${pauseDurationMinutes === 1 ? "" : "s"} of delay.`
        : "Live event resumed."
    );
  }

  function handleAddLiveDelay(minutes = 5) {
    setLiveDelayMinutes((current) => current + minutes);
    showSuccessMessage(`Added ${minutes} minute${minutes === 1 ? "" : "s"} of operational delay.`);
  }

  async function handleAddAssignment(spId = selectedSpId, options?: AddAssignmentOptions) {
    if (!id || !spId) return;

    setSaving(true);
    setAssigningSpId(spId);
    setAssignmentSuccessMessage("");
    setErrorMessage("");
    setEventSaveMessage("");
    setEventSaveError("");

    try {
      const importedPollNote = asText(options?.notes) || getImportedPollNoteForSpId(spId);
      const assignmentNotes = mergeImportedPollNoteIntoAssignmentNotes("", importedPollNote);
      await saveAssignmentRequest("POST", {
        sp_id: spId,
        status: options?.status,
        confirmed: options?.confirmed,
        notes: assignmentNotes || undefined,
      });
    } catch (error) {
      setErrorMessage(error instanceof Error ? error.message : "Could not save assignment.");
      setAssigningSpId("");
      setSaving(false);
      return;
    }

    const refreshed = await refreshData();
    const refreshedAssignments = Array.isArray(refreshed?.assignments) ? refreshed.assignments : [];
    const assignmentNowExists = refreshedAssignments.some(
      (assignment) =>
        asText(assignment.sp_id) === spId &&
        (!options?.status || getAssignmentStatus(assignment) === options.status)
    );

    if (!assignmentNowExists) {
      setErrorMessage("The SP save request completed, but the refreshed event roster did not include that SP. Please refresh the page before continuing.");
      setAssigningSpId("");
      setSaving(false);
      return;
    }

    setRecentAssignedSpId(spId);
    showSuccessMessage(options?.successMessage || "SP assigned");
    window.setTimeout(() => {
      setRecentAssignedSpId("");
    }, 2400);
    setAssigningSpId("");
    setSaving(false);
  }

  async function handleQuickStaffingAdd(status: "confirmed" | "backup") {
    if (!quickStaffingSpId) return;

    const spId = quickStaffingSpId;
    const sp = spsById.get(spId);
    const pollNote = getImportedPollNoteForSpId(spId);

    await handleAddAssignment(spId, {
      status,
      confirmed: status === "confirmed",
      notes: pollNote || undefined,
      successMessage: `${sp ? getFullName(sp) : "SP"} added as ${status === "confirmed" ? "primary" : "backup"}.`,
    });

    setQuickStaffingSpId("");
    setQuickStaffingQuery("");
  }

  async function handleStatusChange(assignment: AssignmentRow, status: AssignmentStatus) {
    setSaving(true);
    setAssigningSpId("");
    setAssignmentSuccessMessage("");
    setErrorMessage("");
    setEventSaveMessage("Saving...");
    setEventSaveError("");

    try {
      const importedPollNote = getImportedPollNoteForSpId(asText(assignment.sp_id));
      const nextNotes = isSelectedStaffingStatus(status)
        ? mergeImportedPollNoteIntoAssignmentNotes(assignment.notes, importedPollNote)
        : asText(assignment.notes);
      const shouldUpdateNotes =
        isSelectedStaffingStatus(status) && asText(importedPollNote) && nextNotes !== asText(assignment.notes);
      await saveAssignmentRequest("PATCH", {
        assignment_id: assignment.id,
        updates: {
          status,
          confirmed: status === "confirmed",
          last_contacted_at:
            status === "contacted" ? new Date().toISOString() : assignment.last_contacted_at,
          ...(shouldUpdateNotes ? { notes: nextNotes || null } : {}),
        },
      });
    } catch (error) {
      setErrorMessage(error instanceof Error ? error.message : "Could not update assignment.");
      setSaving(false);
      return;
    }

    await refreshData();
    showSuccessMessage("Assignment updated.");
    setSaving(false);
  }

