    panelSoft: "linear-gradient(180deg, rgba(248, 252, 255, 0.96) 0%, rgba(240, 247, 252, 0.98) 100%)",
    row: "linear-gradient(180deg, rgba(255, 255, 255, 0.98) 0%, rgba(242, 248, 252, 0.98) 100%)",
    subtle: "rgba(233, 242, 247, 0.72)",
