    borderStrong: "rgba(106, 180, 195, 0.26)",
    text: "#18364a",
    textStrong: "#0f2940",
    textMuted: "#597b8e",
    chip: "rgba(88, 187, 198, 0.12)",
    chipText: "#1b6e7d",
    chipBorder: "rgba(88, 187, 198, 0.22)",
    selectedBg: "rgba(135, 206, 235, 0.18)",
