                          {canManageTrainingAttendance && assignment.training_attended && checkedAt ? (
                            <div style={{ marginTop: "4px", color: "var(--cfsp-green)", fontSize: "10px", fontWeight: 800 }}>
                              Checked in {checkedAt}
                            </div>
                          ) : null}
